// Leccionario diario 2026 — Año Litúrgico A (Mateo), Ferias Año II
// libroId: 49=Mateo, 50=Marcos, 51=Lucas, 52=Juan

export interface GospelEntry {
  titulo: string
  libroId: number
  libroNombre: string
  capitulo: number
  inicio: number
  fin: number
  explicacion: string
}

// Entradas específicas: domingos, fiestas y días especiales
const SPECIFIC: Record<string, GospelEntry> = {
  // ── ENERO ──────────────────────────────────────────────────────────────────
  '2026-01-01': { titulo:'Santa María, Madre de Dios', libroId:51, libroNombre:'San Lucas', capitulo:2, inicio:16, fin:21, explicacion:'María guardaba todas estas cosas y las meditaba en su corazón. Al inicio de cada año, la Iglesia nos invita a contemplar a la Virgen como modelo de fe que acoge la Palabra y la custodia. Que este año comience bajo su mirada maternal.' },
  '2026-01-02': { titulo:'Viernes después de Año Nuevo', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:19, fin:28, explicacion:'Juan el Bautista no dice "yo soy", sino que señala a Otro. El discípulo auténtico no busca brillar por sí mismo sino ser voz que anuncia al Señor que viene.' },
  '2026-01-03': { titulo:'Sábado antes de Epifanía', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:29, fin:34, explicacion:'Juan ve venir a Jesús y proclama: "Este es el Cordero de Dios". La misión de todo creyente es señalar a Cristo en medio del mundo, como hizo el Bautista.' },
  '2026-01-04': { titulo:'Epifanía del Señor', libroId:49, libroNombre:'San Mateo', capitulo:2, inicio:1, fin:12, explicacion:'Los magos recorren un largo camino guiados por una estrella para adorar al recién nacido. Dios se revela no solo a Israel sino a todas las naciones. La búsqueda sincera de Dios siempre termina encontrándolo.' },
  '2026-01-05': { titulo:'Lunes después de Epifanía', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:7, fin:11, explicacion:'Jesús es bautizado y el Padre proclama: "Tú eres mi Hijo amado". Cada bautizado lleva esa misma dignidad: somos hijos amados de Dios, ungidos por el Espíritu.' },
  '2026-01-06': { titulo:'Martes después de Epifanía', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:7, fin:11, explicacion:'El Espíritu desciende sobre Jesús como paloma. El Bautismo no es solo un rito externo; es la entrada en una nueva vida donde el Espíritu mora en nosotros y nos impulsa a vivir como hijos de Dios.' },
  '2026-01-07': { titulo:'Miércoles después de Epifanía', libroId:52, libroNombre:'San Juan', capitulo:2, inicio:1, fin:11, explicacion:'En las bodas de Caná, María intercede y Jesús transforma el agua en vino. Este primer signo revela que Jesús vino a transformar nuestra vida ordinaria en algo nuevo y abundante.' },
  '2026-01-08': { titulo:'Jueves después de Epifanía', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:34, fin:44, explicacion:'Jesús ve la multitud y siente compasión. Con cinco panes y dos peces alimenta a cinco mil personas. La generosidad de Dios supera siempre nuestros cálculos; lo poco que ponemos en sus manos se multiplica.' },
  '2026-01-09': { titulo:'Viernes después de Epifanía', libroId:51, libroNombre:'San Lucas', capitulo:5, inicio:12, fin:16, explicacion:'Un leproso se acerca a Jesús y le dice: "Si quieres, puedes limpiarme". Jesús extiende la mano y lo toca. La voluntad de Dios es siempre sanar, incluir y restaurar a quien la sociedad margina.' },
  '2026-01-10': { titulo:'Sábado después de Epifanía', libroId:52, libroNombre:'San Juan', capitulo:3, inicio:22, fin:30, explicacion:'Juan el Bautista dice: "Es necesario que él crezca y que yo disminuya". Esta actitud de humildad es el modelo del discípulo: decrecer para que Cristo sea todo en nuestra vida.' },
  '2026-01-11': { titulo:'Bautismo del Señor', libroId:49, libroNombre:'San Mateo', capitulo:3, inicio:13, fin:17, explicacion:'Jesús se hace bautizar por Juan para cumplir toda justicia. El Padre lo reconoce públicamente: "Este es mi Hijo amado". Nuestro bautismo nos hace partícipes de esa misma filiación divina.' },
  '2026-01-12': { titulo:'Lunes — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:14, fin:20, explicacion:'Jesús comienza su ministerio proclamando: "El Reino de Dios está cerca". Llama a cuatro pescadores y ellos lo dejan todo para seguirlo. La llamada de Cristo exige una respuesta inmediata y total.' },
  '2026-01-13': { titulo:'Martes — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:21, fin:28, explicacion:'Jesús enseña en la sinagoga y la gente queda asombrada porque habla con autoridad. Incluso los espíritus impuros obedecen su palabra. La enseñanza de Jesús no es teoría; tiene poder para transformar vidas.' },
  '2026-01-14': { titulo:'Miércoles — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:29, fin:39, explicacion:'Jesús sana a la suegra de Pedro y a muchos enfermos, pero al amanecer se retira a orar. La oración es la fuente de donde brota su actividad. También nosotros necesitamos alimentar nuestra misión con momentos de encuentro con el Padre.' },
  '2026-01-15': { titulo:'Jueves — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:1, inicio:40, fin:45, explicacion:'Un leproso excluido de la sociedad se arrodilla ante Jesús. Jesús lo toca y lo sana. Nadie está demasiado impuro o alejado para recibir la misericordia de Dios; él siempre sale al encuentro del que se acerca con fe.' },
  '2026-01-16': { titulo:'Viernes — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:2, inicio:1, fin:12, explicacion:'Cuatro amigos llevan a un paralítico hasta Jesús bajándolo por el techo. Jesús ve su fe y perdona los pecados del enfermo antes de sanarlo. La amistad que conduce al encuentro con Cristo es uno de los mayores regalos que podemos dar.' },
  '2026-01-17': { titulo:'Sábado — Semana 1 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:2, inicio:13, fin:17, explicacion:'Jesús llama a Leví, un publicano cobrador de impuestos, y come con pecadores. "No he venido a llamar a los justos sino a los pecadores." La misericordia de Dios no tiene fronteras ni prejuicios.' },
  '2026-01-18': { titulo:'2º Domingo Tiempo Ordinario', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:29, fin:34, explicacion:'Juan señala a Jesús como el Cordero de Dios que quita el pecado del mundo. Este título evoca al cordero pascual del Éxodo: Jesús es la liberación definitiva de la humanidad. Reconocerlo como Salvador cambia toda nuestra vida.' },
  '2026-01-19': { titulo:'Lunes — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:2, inicio:18, fin:22, explicacion:'Jesús compara su presencia con la alegría de una boda. No se puede poner vino nuevo en odres viejos. El Evangelio exige renovación interior; no basta con añadir prácticas externas a una vida sin conversión.' },
  '2026-01-20': { titulo:'Martes — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:2, inicio:23, fin:28, explicacion:'El sábado fue hecho para el hombre, no el hombre para el sábado. Jesús recuerda que las leyes religiosas están al servicio de la persona, no al revés. La religión auténtica libera, no oprime.' },
  '2026-01-21': { titulo:'Miércoles — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:1, fin:6, explicacion:'Jesús sana en sábado a un hombre con la mano paralizada. Ante la rigidez religiosa de los fariseos, Jesús elige la vida y la compasión. El amor al prójimo siempre está por encima del legalismo.' },
  '2026-01-22': { titulo:'Jueves — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:7, fin:12, explicacion:'Multitudes de todas partes acuden a Jesús porque han escuchado lo que hace. La fama del bien hace que la gente busque a Cristo. Nuestro testimonio de vida puede acercar a otros al Señor.' },
  '2026-01-23': { titulo:'Viernes — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:13, fin:19, explicacion:'Jesús sube al monte y llama a los que él quiere. Elige a doce para que estén con él y para enviarlos a predicar. Primero el estar con Cristo, luego el ir: el apostolado nace de la intimidad con el Señor.' },
  '2026-01-24': { titulo:'Sábado — Semana 2 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:20, fin:21, explicacion:'La familia de Jesús cree que está fuera de sí. La incomprensión es parte del camino del que sigue a Cristo con radicalidad. El discípulo no puede esperar que todos entiendan su elección de vida.' },
  '2026-01-25': { titulo:'3er Domingo — Conversión de San Pablo', libroId:49, libroNombre:'San Mateo', capitulo:4, inicio:12, fin:23, explicacion:'Jesús recorre Galilea predicando el Evangelio del Reino, sanando a los enfermos y llamando a sus primeros discípulos. Su misión abarca tanto la proclamación de la Buena Nueva como la atención a los que sufren. Seguirlo implica participar de esa misma misión integral.' },
  '2026-01-26': { titulo:'Lunes — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:22, fin:30, explicacion:'Jesús responde a quienes lo acusan de actuar por Beelzebú: un reino dividido no puede mantenerse. La obra de Jesús es la de liberar, no la de esclavizar. Quien hace el bien viene de Dios.' },
  '2026-01-27': { titulo:'Martes — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:3, inicio:31, fin:35, explicacion:'La madre y los hermanos de Jesús lo buscan. Él responde señalando a sus discípulos: "Estos son mi madre y mis hermanos". La familia de Dios se construye haciendo su voluntad, no solo por lazos de sangre.' },
  '2026-01-28': { titulo:'Miércoles — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:4, inicio:1, fin:20, explicacion:'La parábola del sembrador muestra cuatro tipos de terreno. La semilla es la misma; lo que varía es la disposición del corazón. Dios siembra con generosidad; de nosotros depende preparar bien el terreno interior.' },
  '2026-01-29': { titulo:'Jueves — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:4, inicio:21, fin:25, explicacion:'La lámpara no se pone bajo el celemín sino sobre el candelero. La fe no es algo privado que se esconde; está llamada a iluminar. Lo que recibimos de Dios es para darlo, no para guardarlo.' },
  '2026-01-30': { titulo:'Viernes — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:4, inicio:26, fin:34, explicacion:'El Reino de Dios es como una semilla que crece sola mientras el labrador duerme. No todo depende de nuestro esfuerzo; hay una fuerza divina que actúa silenciosamente en la historia y en los corazones.' },
  '2026-01-31': { titulo:'Sábado — Semana 3 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:4, inicio:35, fin:41, explicacion:'Los discípulos aterrados despiertan a Jesús durante la tormenta. Él calma el viento y el mar y pregunta: "¿Por qué tienen miedo? ¿No tienen fe?" La presencia de Cristo en nuestra barca no elimina las tormentas pero da la paz que supera toda comprensión.' },

  // ── FEBRERO ────────────────────────────────────────────────────────────────
  '2026-02-01': { titulo:'4º Domingo — Bienaventuranzas', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:1, fin:12, explicacion:'Las Bienaventuranzas son el retrato del discípulo de Jesús. Proponen una lógica completamente distinta a la del mundo: la felicidad no está en el poder o la riqueza sino en la pobreza de espíritu, la misericordia y la paz. Son un programa de vida para el cristiano.' },
  '2026-02-02': { titulo:'Presentación del Señor', libroId:51, libroNombre:'San Lucas', capitulo:2, inicio:22, fin:40, explicacion:'Simeón toma al niño en sus brazos y proclama: "Mis ojos han visto tu salvación". La luz de Cristo ilumina a todos los pueblos. Cada vez que acudimos a la iglesia con fe, Dios nos sale al encuentro como salió al encuentro de Simeón.' },
  '2026-02-03': { titulo:'Martes — Semana 4 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:5, inicio:21, fin:43, explicacion:'Jesús resucita a la hija de Jairo y sana a la mujer con hemorragias. En ambos casos la fe lo hace todo posible. "No temas, solo ten fe": estas palabras de Jesús son para nosotros hoy ante cualquier situación que parezca sin salida.' },
  '2026-02-04': { titulo:'Miércoles — Semana 4 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:1, fin:6, explicacion:'En su propio pueblo Jesús no puede hacer milagros por la falta de fe de los nazarenos. La familiaridad puede apagar la capacidad de asombro. La fe exige apertura y humildad para ver a Dios actuando cerca de nosotros.' },
  '2026-02-05': { titulo:'Jueves — Semana 4 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:7, fin:13, explicacion:'Jesús envía a los doce de dos en dos y les da autoridad sobre los espíritus impuros. Los envía sin llevar nada extra: la misión se hace confiando en Dios, no en los propios recursos. La sencillez es una condición del apostolado.' },
  '2026-02-06': { titulo:'Viernes — Semana 4 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:14, fin:29, explicacion:'El martirio de Juan el Bautista muestra que la fidelidad a la verdad tiene un costo. Juan murió porque no calló ante la injusticia del poderoso. El profeta auténtico dice la verdad aunque le cueste la vida.' },
  '2026-02-07': { titulo:'Sábado — Semana 4 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:30, fin:34, explicacion:'Los apóstoles regresan de su misión y Jesús los invita a descansar. Pero al ver la multitud como ovejas sin pastor, siente compasión. El descanso y la misión se equilibran en la vida del discípulo; el motor de todo es la compasión.' },
  '2026-02-08': { titulo:'5º Domingo — Sal y Luz', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:13, fin:16, explicacion:'Jesús llama a sus discípulos "sal de la tierra" y "luz del mundo". La sal preserva y da sabor; la luz ilumina. El cristiano no debe brillar para sí mismo sino para que otros vean las obras buenas y glorifiquen a Dios.' },
  '2026-02-09': { titulo:'Lunes — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:6, inicio:53, fin:56, explicacion:'En todos los lugares adonde llegaba Jesús, la gente lo reconocía y acudía a tocar el borde de su manto. ¿Cuánto deseo hay en mi corazón de tocar a Jesús, de estar cerca de él? La fe activa busca el contacto con el Señor.' },
  '2026-02-10': { titulo:'Martes — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:7, inicio:1, fin:13, explicacion:'Jesús critica a los fariseos por anteponer la tradición humana al mandamiento de Dios. La religiosidad externa sin conversión interior es hipocresía. Lo que honra a Dios no son los ritos vacíos sino el corazón que ama.' },
  '2026-02-11': { titulo:'Miércoles — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:7, inicio:14, fin:23, explicacion:'Lo que contamina al ser humano no viene de fuera sino de dentro. Del corazón salen los pensamientos malos. La conversión verdadera comienza en lo más profundo de nuestra interioridad, no en los gestos externos.' },
  '2026-02-12': { titulo:'Jueves — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:7, inicio:24, fin:30, explicacion:'Una mujer sirofenicia pide a Jesús que libere a su hija. Ante la respuesta difícil de Jesús, ella no se rinde. Su humildad y persistencia logran lo que pedía. La oración perseverante, aunque no obtenga respuesta inmediata, finalmente es escuchada.' },
  '2026-02-13': { titulo:'Viernes — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:7, inicio:31, fin:37, explicacion:'Jesús sana a un sordomudo poniendo los dedos en sus oídos y tocando su lengua. "Ábrete": esa palabra de Cristo es para nosotros también. Él quiere abrir nuestros oídos a su Palabra y nuestra boca para proclamarla.' },
  '2026-02-14': { titulo:'Sábado — Semana 5 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:8, inicio:1, fin:10, explicacion:'Jesús alimenta a cuatro mil personas con siete panes. Siente compasión de la multitud porque llevan tres días con él. Dios ve nuestra hambre, la física y la espiritual, y tiene poder para saciarla.' },
  '2026-02-15': { titulo:'6º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:17, fin:37, explicacion:'Jesús no vino a abolir la Ley sino a llevarla a su plenitud. Va más allá de la letra: no solo el matar sino el odiar en el corazón es pecado. El Evangelio nos llama a una justicia que supera la del legalismo externo.' },
  '2026-02-16': { titulo:'Lunes — Semana 6 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:8, inicio:11, fin:13, explicacion:'Los fariseos piden a Jesús una señal del cielo. Él se niega. La fe no necesita de señales espectaculares; se nutre de la Palabra y los sacramentos. Pedir señales a Dios como condición para creer es no tener fe.' },
  '2026-02-17': { titulo:'Martes — Semana 6 Tiempo Ordinario', libroId:50, libroNombre:'San Marcos', capitulo:8, inicio:14, fin:21, explicacion:'Jesús advierte sobre la levadura de los fariseos. Haber visto los milagros no es suficiente si el corazón permanece cerrado. La comprensión del Evangelio no es fruto de la inteligencia sino de la apertura del corazón.' },
  '2026-02-18': { titulo:'Miércoles de Ceniza', libroId:49, libroNombre:'San Mateo', capitulo:6, inicio:1, fin:18, explicacion:'Jesús enseña a orar, ayunar y dar limosna en secreto, solo para el Padre. La Cuaresma comienza con una invitación a la autenticidad: que nuestras prácticas religiosas no sean teatro sino encuentro real con Dios. "Tu Padre, que ve en lo secreto, te recompensará."' },
  '2026-02-19': { titulo:'Jueves después de Ceniza', libroId:51, libroNombre:'San Lucas', capitulo:9, inicio:22, fin:25, explicacion:'Jesús anuncia que el Hijo del Hombre debe sufrir, morir y resucitar. Luego invita: "Si alguno quiere seguirme, niéguese a sí mismo, tome su cruz cada día y sígame". La Cuaresma es tiempo de tomar nuestra cruz con generosidad.' },
  '2026-02-20': { titulo:'Viernes después de Ceniza', libroId:49, libroNombre:'San Mateo', capitulo:9, inicio:14, fin:15, explicacion:'Los discípulos de Juan preguntan por qué los de Jesús no ayunan. Él responde que cuando el esposo esté ausente, entonces ayunarán. El ayuno cuaresmal es expresión del deseo de tener a Cristo en nuestra vida.' },
  '2026-02-21': { titulo:'Sábado después de Ceniza', libroId:51, libroNombre:'San Lucas', capitulo:5, inicio:27, fin:32, explicacion:'Leví lo deja todo y sigue a Jesús. La conversión auténtica implica levantarse y seguir. "No he venido a llamar a los justos sino a los pecadores al arrepentimiento": nadie está excluido de esta invitación.' },
  '2026-02-22': { titulo:'1er Domingo de Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:4, inicio:1, fin:11, explicacion:'Jesús es tentado en el desierto durante cuarenta días. Responde a cada tentación con la Palabra de Dios. En Cuaresma somos llamados a identificar las tentaciones de nuestra vida y a vencerlas con la misma arma: la Escritura y la oración.' },
  '2026-02-23': { titulo:'Lunes — Semana 1 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:25, inicio:31, fin:46, explicacion:'El juicio final se decide por el amor al prójimo: dar de comer al hambriento, vestir al desnudo, visitar al enfermo. Lo que hagamos al más pequeño, se lo hacemos a Cristo. La Cuaresma es tiempo de examen sobre cómo tratamos a los más vulnerables.' },
  '2026-02-24': { titulo:'Martes — Semana 1 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:6, inicio:7, fin:15, explicacion:'Jesús enseña el Padre Nuestro. En siete peticiones concentra toda la vida cristiana: la gloria de Dios y las necesidades del hombre. El centro de la oración cuaresmal es esta oración que el Señor mismo nos enseñó.' },
  '2026-02-25': { titulo:'Miércoles — Semana 1 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:11, inicio:29, fin:32, explicacion:'Jesús reprocha a la gente por pedir señales. La única señal es la de Jonás: tres días en el vientre del pez anuncian la muerte y resurrección de Cristo. La Cuaresma nos orienta hacia la Pascua, la señal definitiva de Dios.' },
  '2026-02-26': { titulo:'Jueves — Semana 1 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:7, inicio:7, fin:12, explicacion:'Pedid y recibiréis, buscad y encontraréis. La oración perseverante es señal de fe. Si nosotros siendo malos sabemos dar cosas buenas a nuestros hijos, cuánto más el Padre dará cosas buenas a los que se las pidan.' },
  '2026-02-27': { titulo:'Viernes — Semana 1 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:20, fin:26, explicacion:'Jesús pide una justicia que supere la de los fariseos. No solo no matar sino no guardar ira en el corazón. Antes de ofrecer el don en el altar, reconcíliate con tu hermano. La Cuaresma es tiempo privilegiado de reconciliación.' },
  '2026-02-28': { titulo:'Sábado — Semana 1 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:43, fin:48, explicacion:'Amad a vuestros enemigos y orad por los que os persiguen. Esta exigencia radical es el corazón del Evangelio. Dios hace salir su sol sobre buenos y malos. Ser "perfectos como el Padre" es imitar su amor universal e incondicional.' },

  // ── MARZO ──────────────────────────────────────────────────────────────────
  '2026-03-01': { titulo:'2º Domingo de Cuaresma — Transfiguración', libroId:49, libroNombre:'San Mateo', capitulo:17, inicio:1, fin:9, explicacion:'En el monte Tabor, Jesús se transfigura ante Pedro, Santiago y Juan. El Padre proclama: "Este es mi Hijo amado". Este momento de gloria anticipa la Resurrección. La Cuaresma no es solo penitencia; lleva hacia la luz pascual.' },
  '2026-03-02': { titulo:'Lunes — Semana 2 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:6, inicio:36, fin:38, explicacion:'Sed misericordiosos como vuestro Padre es misericordioso. No juzguéis y no seréis juzgados. La generosidad que damos a otros regresa a nosotros multiplicada. La Cuaresma nos llama a cultivar la misericordia en el corazón.' },
  '2026-03-03': { titulo:'Martes — Semana 2 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:23, inicio:1, fin:12, explicacion:'Jesús critica a los escribas que dicen pero no hacen. El mayor entre vosotros será vuestro servidor. La autoridad en la Iglesia y en la vida no es poder sino servicio. La humildad es la medida de la grandeza según el Evangelio.' },
  '2026-03-04': { titulo:'Miércoles — Semana 2 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:20, inicio:17, fin:28, expresacion:'Los hijos de Zebedeo piden los primeros puestos. Jesús responde: el que quiera ser grande, que sea servidor. Él mismo no vino a ser servido sino a servir y dar su vida. El camino a la grandeza pasa por el servicio generoso.' },
  '2026-03-04': { titulo:'Miércoles — Semana 2 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:20, inicio:17, fin:28, explicacion:'Los hijos de Zebedeo piden los primeros puestos. Jesús responde: el que quiera ser grande, que sea servidor. Él mismo no vino a ser servido sino a servir y dar su vida. El camino a la grandeza pasa por el servicio generoso.' },
  '2026-03-05': { titulo:'Jueves — Semana 2 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:16, inicio:19, fin:31, explicacion:'El rico Epulón y el pobre Lázaro: después de la muerte, los roles se invierten. La indiferencia ante el sufrimiento del prójimo tiene consecuencias eternas. "Tienen a Moisés y a los profetas; que los escuchen": la Palabra de Dios es el camino de la conversión.' },
  '2026-03-06': { titulo:'Viernes — Semana 2 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:21, inicio:33, fin:46, explicacion:'La parábola de los viñadores homicidas es la historia de la salvación: Dios envía a sus profetas y finalmente a su Hijo. El Hijo es rechazado pero la piedra desechada se convierte en piedra angular. La Pascua es el cumplimiento de esta historia.' },
  '2026-03-07': { titulo:'Sábado — Semana 2 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:15, inicio:1, fin:32, explicacion:'La parábola del hijo pródigo revela el corazón de Dios: el Padre corre al encuentro del hijo que regresa arrepentido. Dios no espera que lleguemos completamente convertidos; sale a nuestro encuentro a mitad del camino.' },
  '2026-03-08': { titulo:'3er Domingo de Cuaresma — La Samaritana', libroId:52, libroNombre:'San Juan', capitulo:4, inicio:5, fin:42, explicacion:'Jesús pide agua a una mujer samaritana y le ofrece el agua que sacia para siempre. El diálogo transforma la vida de esta mujer y ella se convierte en misionera de su pueblo. Cristo busca a cada persona donde está y le ofrece vida nueva.' },
  '2026-03-09': { titulo:'Lunes — Semana 3 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:4, inicio:24, fin:30, explicacion:'Ningún profeta es bien recibido en su tierra. Jesús recuerda que Dios actuó con generosidad con extranjeros como la viuda de Sarepta y Naamán. La salvación no es privilegio exclusivo de ningún grupo; la misericordia de Dios supera todas las fronteras.' },
  '2026-03-10': { titulo:'Martes — Semana 3 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:18, inicio:21, fin:35, explicacion:'Pedro pregunta cuántas veces debe perdonar. Jesús responde: setenta veces siete, es decir, sin límite. Quien ha recibido el perdón inmenso de Dios no puede negarlo a su hermano. El perdón no es debilidad; es la fuerza del amor.' },
  '2026-03-11': { titulo:'Miércoles — Semana 3 Cuaresma', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:17, fin:19, explicacion:'Jesús no vino a abolir la Ley sino a cumplirla. Quien practica y enseña los mandamientos será grande en el Reino. La Cuaresma es tiempo de volver a lo esencial: amar a Dios y al prójimo como cumplimiento de toda la Ley.' },
  '2026-03-12': { titulo:'Jueves — Semana 3 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:11, inicio:14, fin:23, explicacion:'El que no está conmigo está contra mí. No hay neutralidad frente a Cristo. El que recoge con él no dispersa. La Cuaresma nos invita a examinarnos: ¿estoy verdaderamente con Cristo o vivo una fe tibia?' },
  '2026-03-13': { titulo:'Viernes — Semana 3 Cuaresma', libroId:50, libroNombre:'San Marcos', capitulo:12, inicio:28, fin:34, explicacion:'Un escriba pregunta cuál es el primer mandamiento. Jesús responde: amar a Dios con todo el corazón y al prójimo como a uno mismo. "No estás lejos del Reino de Dios." La doble caridad es el corazón del Evangelio.' },
  '2026-03-14': { titulo:'Sábado — Semana 3 Cuaresma', libroId:51, libroNombre:'San Lucas', capitulo:18, inicio:9, fin:14, explicacion:'El fariseo y el publicano oran en el Templo. El que se humilla será exaltado. La oración verdadera reconoce nuestra pequeñez ante Dios y clama su misericordia. "Ten piedad de mí, que soy pecador": esta es la oración que Dios escucha.' },
  '2026-03-15': { titulo:'4º Domingo de Cuaresma — El Ciego de Nacimiento', libroId:52, libroNombre:'San Juan', capitulo:9, inicio:1, fin:41, explicacion:'Jesús sana al ciego de nacimiento y lo ilumina también espiritualmente. Los fariseos que creen ver quedan ciegos por su soberbia. Cristo es la luz del mundo que abre los ojos de quienes reconocen su ceguera y buscan la verdad.' },
  '2026-03-16': { titulo:'Lunes — Semana 4 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:4, inicio:43, fin:54, explicacion:'Un funcionario pide a Jesús que sane a su hijo agonizante. Jesús le dice que regrese, que su hijo vive. Él creyó en la palabra de Jesús y se fue. La fe que actúa sobre la Palabra de Cristo produce milagros aún sin ver.' },
  '2026-03-17': { titulo:'Martes — Semana 4 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:5, inicio:1, fin:16, explicacion:'Jesús sana al paralítico de la piscina de Betesda que llevaba 38 años enfermo. Le dice: "Levántate, toma tu camilla y anda". La palabra de Cristo tiene poder para sanar las parálisis más antiguas de nuestra vida.' },
  '2026-03-18': { titulo:'Miércoles — Semana 4 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:5, inicio:17, fin:30, explicacion:'El Padre y el Hijo trabajan juntos. Jesús hace solo lo que ve hacer al Padre. El Hijo resucitará a los muertos y juzgará a los vivos. Contemplar la unidad entre Jesús y el Padre es fundamento de nuestra fe y esperanza.' },
  '2026-03-19': { titulo:'San José, Esposo de la Virgen María', libroId:49, libroNombre:'San Mateo', capitulo:1, inicio:16, fin:24, explicacion:'José, hombre justo, acoge a María y al niño que viene del Espíritu Santo. Su fe silenciosa y obediente lo hace custodio de la Sagrada Familia. José nos enseña que la grandeza cristiana no está en las palabras sino en el cumplimiento fiel de la voluntad de Dios.' },
  '2026-03-20': { titulo:'Viernes — Semana 4 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:7, inicio:1, fin:30, explicacion:'Jesús enseña en el Templo y los jefes intentan arrestarlo. "Mi doctrina no es mía sino del que me envió." Jesús actúa siempre desde la obediencia al Padre. La Cuaresma nos llama a orientar nuestra vida hacia la voluntad de Dios.' },
  '2026-03-21': { titulo:'Sábado — Semana 4 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:7, inicio:40, fin:53, explicacion:'El pueblo se divide ante Jesús. Unos dicen que es el profeta; otros, el Cristo; otros lo rechazan. Jesús siempre divide porque propone una opción radical. Ante él no hay posición neutral: hay que decidir.' },
  '2026-03-22': { titulo:'5º Domingo de Cuaresma — Resurrección de Lázaro', libroId:52, libroNombre:'San Juan', capitulo:11, inicio:1, fin:45, explicacion:'Jesús llora ante la tumba de Lázaro y luego lo resucita. "Yo soy la resurrección y la vida; el que cree en mí, aunque muera, vivirá." La Cuaresma avanza hacia el misterio central: Cristo es señor sobre la muerte.' },
  '2026-03-23': { titulo:'Lunes — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:8, inicio:1, fin:11, explicacion:'La mujer adúltera es traída ante Jesús para ser lapidada. Él no condena sino que perdona y llama a no pecar más. La misericordia de Dios no ignora el pecado; lo perdona y llama a la conversión. Nadie está condenado ante Cristo.' },
  '2026-03-24': { titulo:'Martes — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:8, inicio:21, fin:30, explicacion:'Jesús dice: cuando levantéis al Hijo del Hombre, conoceréis que Yo Soy. La cruz es el momento de la revelación plena. Cuanto más nos acercamos a la Semana Santa, más contemplamos el amor de Dios que se entrega sin reservas.' },
  '2026-03-25': { titulo:'Anunciación del Señor', libroId:51, libroNombre:'San Lucas', capitulo:1, inicio:26, fin:38, explicacion:'El ángel saluda a María: "Alégrate, llena de gracia". María pregunta cómo puede ser y luego responde: "Heme aquí, soy la sierva del Señor". Su "sí" libre y obediente es el modelo de toda vocación cristiana.' },
  '2026-03-26': { titulo:'Jueves — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:8, inicio:51, fin:59, expresacion:'Antes de que Abraham existiera, Yo Soy. Jesús afirma su preexistencia eterna. Esta afirmación escandaliza a sus oyentes pero revela su identidad divina. Creer en Cristo significa creer en el Hijo eterno de Dios hecho hombre.' },
  '2026-03-26': { titulo:'Jueves — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:8, inicio:51, fin:59, explicacion:'Antes de que Abraham existiera, Yo Soy. Jesús afirma su preexistencia eterna. Esta afirmación escandaliza a sus oyentes pero revela su identidad divina. Creer en Cristo significa creer en el Hijo eterno de Dios hecho hombre.' },
  '2026-03-27': { titulo:'Viernes — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:10, inicio:31, fin:42, explicacion:'Los judíos quieren apedrear a Jesús porque dice que el Padre y él son uno. Muchos sin embargo creen en él. La identidad de Jesús divide: para unos es blasfemia, para otros es la revelación que da vida. La fe es una decisión personal.' },
  '2026-03-28': { titulo:'Sábado — Semana 5 Cuaresma', libroId:52, libroNombre:'San Juan', capitulo:11, inicio:45, fin:56, explicacion:'Caifás profetiza sin saberlo: "conviene que un hombre muera por el pueblo". La decisión de matar a Jesús está tomada. Él se retira pero sabe que su hora se acerca. La entrega de Cristo es libre y consciente: nadie le quita la vida.' },
  '2026-03-29': { titulo:'Domingo de Ramos — Pasión del Señor', libroId:49, libroNombre:'San Mateo', capitulo:21, inicio:1, fin:11, explicacion:'Jesús entra en Jerusalén sobre un asno mientras la multitud lo aclama. Pero esta misma semana la multitud pedirá su crucifixión. La liturgia hoy proclama la Pasión completa. Acompañamos a Cristo en el camino de la cruz que lleva a la Resurrección.' },
  '2026-03-30': { titulo:'Lunes de Semana Santa', libroId:52, libroNombre:'San Juan', capitulo:12, inicio:1, fin:11, explicacion:'María unge los pies de Jesús con perfume costoso y los seca con su cabello. Judas protesta. Jesús defiende el gesto: "Déjala, pues lo ha guardado para el día de mi sepultura". El amor extravagante a Jesús siempre vale la pena.' },
  '2026-03-31': { titulo:'Martes de Semana Santa', libroId:52, libroNombre:'San Juan', capitulo:13, inicio:21, fin:38, explicacion:'En la última cena Jesús anuncia la traición de Judas y la negación de Pedro. Dos discípulos cercanos lo fallarán. Pero Jesús no los rechaza; sigue amando hasta el final. Ninguna de nuestras infidelidades agota la paciencia de Cristo.' },

  // ── ABRIL ──────────────────────────────────────────────────────────────────
  '2026-04-01': { titulo:'Miércoles de Semana Santa', libroId:49, libroNombre:'San Mateo', capitulo:26, inicio:14, fin:25, explicacion:'Judas pacta con los sumos sacerdotes la entrega de Jesús por treinta monedas de plata. En la cena, Jesús lo identifica como el traidor. La traición de Judas contrasta con el amor fiel de Cristo. Jesús nunca traiciona; somos nosotros quienes a veces lo vendemos.' },
  '2026-04-02': { titulo:'Jueves Santo — Institución de la Eucaristía', libroId:52, libroNombre:'San Juan', capitulo:13, inicio:1, fin:15, explicacion:'Jesús lava los pies a sus discípulos antes de la cena. "Yo, el Señor y el Maestro, les he lavado los pies; también ustedes deben lavarse los pies unos a otros." La Eucaristía y el servicio son inseparables: recibir a Cristo exige servir al hermano.' },
  '2026-04-03': { titulo:'Viernes Santo', libroId:52, libroNombre:'San Juan', capitulo:18, inicio:1, fin:42, explicacion:'La Pasión de Juan presenta a Jesús como rey que reina desde la cruz. No hay grito de abandono; Jesús entrega libremente su vida. "Todo está cumplido." La cruz no es una derrota sino el acto supremo del amor de Dios por la humanidad.' },
  '2026-04-05': { titulo:'Domingo de Pascua — Resurrección del Señor', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:1, fin:9, explicacion:'María Magdalena corre al sepulcro y lo encuentra vacío. Pedro y el discípulo amado corren y ven los lienzos en el suelo. "Vio y creyó." La Resurrección es el fundamento de nuestra fe: Cristo vive y nosotros viviremos con él.' },
  '2026-04-06': { titulo:'Lunes de Pascua', libroId:49, libroNombre:'San Mateo', capitulo:28, inicio:8, fin:15, explicacion:'Las mujeres salen del sepulcro con miedo pero llenas de alegría. Se encuentran con el Resucitado que las envía a anunciar la buena nueva. El primer anuncio de la Resurrección fue confiado a mujeres: el Evangelio transforma la historia.' },
  '2026-04-07': { titulo:'Martes de Pascua', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:11, fin:18, explicacion:'María Magdalena permanece llorando junto al sepulcro. El Resucitado la llama por su nombre: "¡María!" El buen pastor conoce a sus ovejas y las llama por su nombre. El encuentro personal con Cristo transforma el llanto en misión.' },
  '2026-04-08': { titulo:'Miércoles de Pascua — Discípulos de Emaús', libroId:51, libroNombre:'San Lucas', capitulo:24, inicio:13, fin:35, explicacion:'Dos discípulos desanimados caminan hacia Emaús. El Resucitado los acompaña, explica las Escrituras y se revela en la fracción del pan. Cuando los ojos se abren, él desaparece porque ya vive en ellos. La Eucaristía es el lugar del encuentro con el Resucitado.' },
  '2026-04-09': { titulo:'Jueves de Pascua', libroId:51, libroNombre:'San Lucas', capitulo:24, inicio:35, fin:48, explicacion:'Jesús se aparece a los Once y les muestra sus manos y pies. Come ante ellos para demostrar que no es un fantasma. Abre su mente para que entiendan las Escrituras. La Resurrección es corporal, real; no es una ilusión sino la victoria definitiva sobre la muerte.' },
  '2026-04-10': { titulo:'Viernes de Pascua', libroId:52, libroNombre:'San Juan', capitulo:21, inicio:1, fin:14, explicacion:'Los discípulos pescan toda la noche sin éxito. Al amanecer, el Resucitado les dice que echen la red al lado derecho y la red se llena. El Resucitado sigue acompañando nuestros esfuerzos y los hace fructificar cuando confiamos en su Palabra.' },
  '2026-04-11': { titulo:'Sábado de Pascua', libroId:50, libroNombre:'San Marcos', capitulo:16, inicio:9, fin:15, explicacion:'El Resucitado se aparece primero a María Magdalena y luego a los Once. Les reprocha su incredulidad y dureza de corazón. Luego los envía a predicar el Evangelio a toda la creación. La Resurrección es el fundamento y el impulso de la misión.' },
  '2026-04-12': { titulo:'2º Domingo de Pascua — Santo Tomás', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:19, fin:31, explicacion:'Tomás no cree hasta ver las heridas del Resucitado. Jesús se las muestra y Tomás proclama: "¡Señor mío y Dios mío!" "Dichosos los que no vieron y creyeron." La fe en la Resurrección no requiere ver con los ojos sino abrirse al testimonio de la Iglesia.' },
  '2026-04-13': { titulo:'Lunes — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:3, inicio:1, fin:8, explicacion:'Nicodemo viene de noche a Jesús. Jesús le habla del nacimiento del agua y del Espíritu. El bautismo es un nuevo nacimiento: no se nace cristiano por sangre sino por el Espíritu. La Pascua celebra este nuevo nacimiento para todos los bautizados.' },
  '2026-04-14': { titulo:'Martes — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:3, inicio:7, fin:15, explicacion:'Así como Moisés levantó la serpiente en el desierto, el Hijo del Hombre debe ser levantado para que todo el que crea en él tenga vida eterna. La cruz es el lugar donde se contempla el amor de Dios y se encuentra la salvación.' },
  '2026-04-15': { titulo:'Miércoles — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:3, inicio:16, fin:21, explicacion:'Porque tanto amó Dios al mundo que le dio a su Hijo único para que todo el que crea en él no muera sino que tenga vida eterna. Este versículo es el corazón del Evangelio. El amor de Dios es la razón de todo; no vino a condenar sino a salvar.' },
  '2026-04-16': { titulo:'Jueves — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:3, inicio:31, fin:36, explicacion:'El que viene de arriba está por encima de todos. El Padre ama al Hijo y ha puesto todo en sus manos. El que cree en el Hijo tiene vida eterna. La fe en Jesús Resucitado es la puerta a la vida que no termina.' },
  '2026-04-17': { titulo:'Viernes — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:1, fin:15, explicacion:'Jesús alimenta a cinco mil personas con cinco panes y dos peces. Todos comen hasta saciarse y sobran doce canastos. La generosidad de Dios supera siempre nuestras necesidades. La multiplicación anticipa la Eucaristía: Cristo se da en abundancia.' },
  '2026-04-18': { titulo:'Sábado — Semana 2 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:16, fin:21, explicacion:'Jesús camina sobre el mar y dice a los discípulos aterrados: "Soy yo, no teman." En medio de las tormentas de la vida, el Resucitado viene a nuestro encuentro y con su presencia trae la paz.' },
  '2026-04-19': { titulo:'3er Domingo de Pascua — Camino de Emaús', libroId:51, libroNombre:'San Lucas', capitulo:24, inicio:13, fin:35, explicacion:'El corazón de los discípulos de Emaús ardía mientras Jesús les explicaba las Escrituras. Lo reconocen en la fracción del pan y corren a anunciarlo. La Misa tiene la misma estructura: Palabra y Eucaristía, explicación de las Escrituras y encuentro con el Resucitado.' },
  '2026-04-20': { titulo:'Lunes — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:22, fin:29, explicacion:'La gente busca a Jesús por los panes que comieron. Él los invita a trabajar no por el alimento que perece sino por el que dura para la vida eterna. El Señor quiere orientar nuestros deseos hacia lo que realmente sacia: él mismo.' },
  '2026-04-21': { titulo:'Martes — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:30, fin:35, explicacion:'La gente pide una señal. Jesús responde: "Yo soy el pan de vida; el que viene a mí no tendrá hambre y el que cree en mí nunca tendrá sed." Cristo es la respuesta a toda necesidad humana profunda. Él es el alimento del alma.' },
  '2026-04-22': { titulo:'Miércoles — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:35, fin:40, explicacion:'Todo el que vea al Hijo y crea en él tendrá vida eterna y yo lo resucitaré el último día. La voluntad del Padre es que nadie se pierda. La fe en Jesús Resucitado garantiza la resurrección final.' },
  '2026-04-23': { titulo:'Jueves — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:44, fin:51, explicacion:'Nadie puede venir a mí si el Padre no lo atrae. La fe es un don que viene de Dios, pero exige nuestra cooperación. "Yo soy el pan vivo bajado del cielo": Jesús se ofrece como alimento eterno para quienes creen en él.' },
  '2026-04-24': { titulo:'Viernes — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:52, fin:59, explicacion:'El que come mi carne y bebe mi sangre tiene vida eterna y yo lo resucitaré. La Eucaristía no es un símbolo; es el cuerpo y la sangre reales de Cristo. Participar en la misa con fe es alimentarse del mismo Resucitado.' },
  '2026-04-25': { titulo:'Sábado — Semana 3 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:60, fin:69, explicacion:'Muchos discípulos se escandalizan y se van. Jesús pregunta a los doce si también ellos quieren irse. Pedro responde: "¿A quién iremos? Tú tienes palabras de vida eterna." Esta confesión de fe es la nuestra también: no hay otro camino.' },
  '2026-04-26': { titulo:'4º Domingo de Pascua — Buen Pastor', libroId:52, libroNombre:'San Juan', capitulo:10, inicio:1, fin:10, explicacion:'Yo soy la puerta de las ovejas. El ladrón viene a robar y matar; yo vine para que tengan vida y la tengan en abundancia. Cristo es la única puerta hacia la vida plena. El pastor auténtico da la vida por sus ovejas.' },
  '2026-04-27': { titulo:'Lunes — Semana 4 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:10, inicio:11, fin:18, explicacion:'Yo soy el buen pastor: conozco a mis ovejas y ellas me conocen a mí, como el Padre me conoce a mí. El buen pastor da la vida por las ovejas. Esta entrega total de Cristo en la cruz es el modelo de todo amor auténtico.' },
  '2026-04-28': { titulo:'Martes — Semana 4 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:10, inicio:22, fin:30, explicacion:'Mis ovejas escuchan mi voz; yo las conozco y ellas me siguen, y yo les doy vida eterna. El Padre y yo somos uno. La relación del cristiano con Cristo es personal, de escucha y seguimiento. Nadie puede arrebatarnos de sus manos.' },
  '2026-04-29': { titulo:'Miércoles — Semana 4 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:12, inicio:44, fin:50, explicacion:'El que cree en mí no cree en mí sino en el que me envió. Yo soy la luz que ha venido al mundo para que todo el que crea en mí no permanezca en las tinieblas. Creer en Jesús es abrirse a la luz que ilumina toda la existencia.' },
  '2026-04-30': { titulo:'Jueves — Semana 4 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:13, inicio:16, fin:20, explicacion:'El que acoge al que yo envíe, me acoge a mí. El enviado no es mayor que el que lo envía. Recibir a los misioneros y testigos del Evangelio es recibir al mismo Cristo. El servicio al prójimo tiene una dimensión divina.' },

  // ── MAYO ──────────────────────────────────────────────────────────────────
  '2026-05-01': { titulo:'San José Obrero', libroId:49, libroNombre:'San Mateo', capitulo:13, inicio:54, fin:58, explicacion:'En Nazaret preguntan asombrados: "¿No es este el hijo del carpintero?" José, el padre adoptivo, enseñó a Jesús el oficio. El trabajo honrado tiene una dimensión sagrada; José santificó el trabajo artesano y nos muestra que lo cotidiano puede ser santificado.' },
  '2026-05-03': { titulo:'5º Domingo de Pascua — Camino y Verdad', libroId:52, libroNombre:'San Juan', capitulo:14, inicio:1, fin:12, explicacion:'No se turbe vuestro corazón. En la casa del Padre hay muchas moradas. Yo soy el camino, la verdad y la vida. Nadie va al Padre sino por mí. Cristo no es uno de los caminos; es el camino único que conduce al Padre.' },
  '2026-05-04': { titulo:'Lunes — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:14, inicio:21, fin:26, explicacion:'El que me ama guardará mi Palabra y mi Padre lo amará. El Paráclito os enseñará todo y os recordará todo lo que yo os he dicho. El amor a Cristo se demuestra guardando su Palabra, y el Espíritu nos ayuda a comprenderla profundamente.' },
  '2026-05-05': { titulo:'Martes — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:14, inicio:27, fin:31, explicacion:'Mi paz os dejo, mi paz os doy. No os la doy como la da el mundo. No se turbe vuestro corazón ni se acobarde. La paz de Cristo es diferente a la paz mundana: es interior, profunda, independiente de las circunstancias externas.' },
  '2026-05-06': { titulo:'Miércoles — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:15, inicio:1, fin:8, explicacion:'Yo soy la vid, vosotros los sarmientos. El que permanece en mí y yo en él, ese da mucho fruto. Separados de mí no podéis hacer nada. La vida espiritual fructífera brota de la unión con Cristo, no del esfuerzo propio.' },
  '2026-05-07': { titulo:'Jueves — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:15, inicio:9, fin:11, explicacion:'Permaneced en mi amor. Si guardáis mis mandamientos permaneceréis en mi amor, como yo he guardado los mandamientos de mi Padre y permanezco en su amor. Os digo esto para que mi alegría esté en vosotros y vuestra alegría sea plena.' },
  '2026-05-08': { titulo:'Viernes — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:15, inicio:12, fin:17, explicacion:'Este es mi mandamiento: que os améis unos a otros como yo os he amado. No hay amor más grande que dar la vida por los amigos. Os llamo amigos porque os he comunicado todo lo que oí de mi Padre. La amistad con Cristo es el don más grande.' },
  '2026-05-09': { titulo:'Sábado — Semana 5 de Pascua', libroId:52, libroNombre:'San Juan', capitulo:15, inicio:18, fin:21, explicacion:'Si el mundo os odia, recordad que a mí me odió antes. Porque no sois del mundo sino que yo os he elegido. El discípulo no debe esperar la aprobación del mundo; su identidad viene de haber sido elegido por Cristo.' },
  '2026-05-10': { titulo:'6º Domingo de Pascua', libroId:52, libroNombre:'San Juan', capitulo:14, inicio:15, fin:21, explicacion:'Si me amáis guardaréis mis mandamientos. Yo rogaré al Padre que os dé otro Paráclito que esté siempre con vosotros. El que me ama será amado por mi Padre y yo lo amaré. El amor a Cristo trae la presencia del Espíritu y del Padre.' },
  '2026-05-14': { titulo:'San Matthías, Apóstol', libroId:52, libroNombre:'San Juan', capitulo:15, inicio:9, fin:17, explicacion:'No me elegisteis vosotros a mí, sino que yo os elegí a vosotros y os destiné para que vayáis y deis fruto. Matthías fue elegido para completar el colegio apostólico. La vocación no es mérito propio sino don del amor gratuito de Dios.' },
  '2026-05-17': { titulo:'7º Domingo de Pascua — Oración sacerdotal', libroId:52, libroNombre:'San Juan', capitulo:17, inicio:1, fin:11, explicacion:'Padre, la hora ha llegado; glorifica a tu Hijo para que el Hijo te glorifique a ti. Jesús ora por sus discípulos antes de su pasión. Esta oración es la más íntima del corazón de Cristo: pide la unidad y la gloria para quienes creen en él.' },
  '2026-05-24': { titulo:'Pentecostés', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:19, fin:23, explicacion:'El Resucitado aparece a los discípulos, les muestra sus heridas, les da la paz y sopla sobre ellos: "Recibid el Espíritu Santo". El Espíritu es el don pascual por excelencia. La Iglesia nace cuando los discípulos reciben el aliento del Resucitado.' },
  '2026-05-25': { titulo:'Lunes — María, Madre de la Iglesia', libroId:52, libroNombre:'San Juan', capitulo:19, inicio:25, fin:34, explicacion:'Junto a la cruz estaba María. Jesús dice al discípulo amado: "Ahí tienes a tu madre." Desde ese momento el discípulo la acogió en su casa. María es madre de todos los discípulos. Su presencia en la Iglesia es materna, protectora y orante.' },
  '2026-05-31': { titulo:'Santísima Trinidad', libroId:49, libroNombre:'San Mateo', capitulo:28, inicio:16, fin:20, explicacion:'Id y haced discípulos a todas las naciones, bautizándolos en el nombre del Padre, del Hijo y del Espíritu Santo. La misión de la Iglesia nace del misterio trinitario. El bautismo nos introduce en la comunión de amor que es la Trinidad.' },

  // ── JUNIO ──────────────────────────────────────────────────────────────────
  '2026-06-07': { titulo:'Corpus Christi', libroId:52, libroNombre:'San Juan', capitulo:6, inicio:51, fin:58, explicacion:'El que come este pan vivirá para siempre. Mi carne es verdadera comida y mi sangre es verdadera bebida. Corpus Christi celebra la presencia real de Cristo en la Eucaristía. Cada vez que comulgamos, recibimos el mismo Resucitado que vence la muerte.' },
  '2026-06-12': { titulo:'Sagrado Corazón de Jesús', libroId:51, libroNombre:'San Lucas', capitulo:15, inicio:3, fin:7, explicacion:'La parábola de la oveja perdida revela el corazón de Dios: el pastor deja las noventa y nueve para buscar la que se perdió. Hay más alegría en el cielo por un pecador que se convierte que por noventa y nueve justos. Dios busca a cada uno con amor apasionado.' },
  '2026-06-13': { titulo:'Sábado — Inmaculado Corazón de María', libroId:51, libroNombre:'San Lucas', capitulo:2, inicio:41, fin:51, explicacion:'María guardaba todas estas cosas en su corazón. El corazón de María es el corazón que medita, que calla y que custodia la Palabra. Su corazón inmaculado es modelo del corazón del discípulo: recibe a Jesús y lo conserva con amor.' },
  '2026-06-14': { titulo:'11º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:9, inicio:36, fin:43, explicacion:'Jesús ve la multitud como ovejas sin pastor y siente compasión. La mies es mucha y los obreros pocos. Pedid al dueño de la mies que mande obreros a su mies. La misión nace de la compasión de Cristo que se transmite a quienes lo siguen.' },
  '2026-06-21': { titulo:'12º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:10, inicio:26, fin:33, explicacion:'No temáis a los que matan el cuerpo. Vosotros valéis más que muchos gorriones. Todo el que me reconozca ante los hombres, yo también lo reconoceré ante mi Padre. El temor de Dios libera de todo miedo humano.' },
  '2026-06-24': { titulo:'Natividad de San Juan Bautista', libroId:51, libroNombre:'San Lucas', capitulo:1, inicio:57, fin:80, explicacion:'Nace el precursor y su padre Zacarías recupera el habla para proclamar el Benedictus. Juan será profeta del Altísimo, que va delante del Señor a preparar sus caminos. Cada bautizado está llamado a ser precursor que prepara el camino de Cristo en su entorno.' },
  '2026-06-28': { titulo:'13º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:10, inicio:37, fin:42, explicacion:'El que ama a su padre o madre más que a mí no es digno de mí. El que recibe a un profeta por ser profeta recibirá la recompensa del profeta. Seguir a Cristo exige una prioridad absoluta; y el más pequeño servicio hecho por su nombre tiene valor eterno.' },
  '2026-06-29': { titulo:'San Pedro y San Pablo, Apóstoles', libroId:49, libroNombre:'San Mateo', capitulo:16, inicio:13, fin:19, explicacion:'Tú eres Pedro y sobre esta piedra edificaré mi Iglesia. A ti te daré las llaves del Reino de los cielos. La confesión de fe de Pedro es el fundamento de la Iglesia. La Iglesia no es una institución humana sino el cuerpo de Cristo sostenido por su promesa.' },

  // ── JULIO ──────────────────────────────────────────────────────────────────
  '2026-07-05': { titulo:'14º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:11, inicio:25, fin:30, explicacion:'Te bendigo, Padre, porque has ocultado estas cosas a los sabios y las has revelado a los sencillos. Venid a mí todos los que estáis cansados y agobiados que yo os aliviaré. Mi yugo es llevadero y mi carga ligera. Cristo es descanso para los corazones cansados.' },
  '2026-07-12': { titulo:'15º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:13, inicio:1, fin:23, explicacion:'El sembrador salió a sembrar. La semilla es la Palabra de Dios; los terrenos son los diferentes corazones que la reciben. El fruto depende de la disposición interior. La Cuaresma y el tiempo ordinario son para preparar el terreno del corazón.' },
  '2026-07-19': { titulo:'16º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:13, inicio:24, fin:43, explicacion:'La parábola de la cizaña entre el trigo nos enseña paciencia: Dios no arranca la cizaña para no dañar el trigo. El juicio final separará el bien del mal. Mientras tanto, somos llamados a sembrar bien y confiar en Dios para el resto.' },
  '2026-07-22': { titulo:'Santa María Magdalena', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:1, fin:18, explicacion:'María Magdalena es la primera testigo de la Resurrección. El Resucitado la llama por su nombre y ella lo reconoce. El amor apasionado de María Magdalena a Cristo es recompensado con la primera aparición. El amor fiel siempre encuentra a Cristo.' },
  '2026-07-25': { titulo:'Santiago, Apóstol', libroId:49, libroNombre:'San Mateo', capitulo:20, inicio:20, fin:28, explicacion:'La madre de Santiago y Juan pide para sus hijos los primeros puestos. Jesús pregunta si pueden beber su cáliz. El primero entre vosotros será vuestro esclavo. La grandeza en el Reino de Dios se mide por el servicio, no por el poder.' },
  '2026-07-26': { titulo:'17º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:13, inicio:44, fin:52, explicacion:'El Reino de los cielos es como un tesoro escondido, como una perla de gran valor: por ellos el hombre lo vende todo para comprarlo. El discípulo que ha descubierto a Cristo sabe que vale infinitamente más que todo lo demás y lo da todo con alegría.' },

  // ── AGOSTO ────────────────────────────────────────────────────────────────
  '2026-08-02': { titulo:'18º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:14, inicio:13, fin:21, explicacion:'Con cinco panes y dos peces Jesús alimenta a cinco mil personas. Lo que en nuestras manos parece poco, en las de Cristo se multiplica. Dar lo que tenemos a Jesús es el primer paso; él hace el resto.' },
  '2026-08-06': { titulo:'Transfiguración del Señor', libroId:49, libroNombre:'San Mateo', capitulo:17, inicio:1, fin:9, explicacion:'Jesús se transfigura en el monte y su rostro brilla como el sol. La voz del Padre proclama: "Este es mi Hijo amado, escuchadle." La Transfiguración anticipa la gloria de la Resurrección. Escuchar a Cristo es el camino hacia esa misma gloria.' },
  '2026-08-09': { titulo:'19º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:14, inicio:22, fin:33, explicacion:'Pedro camina sobre el agua hacia Jesús pero al ver el viento se hunde y grita: "Señor, sálvame". Jesús lo agarra. "¿Por qué dudaste?" La fe que se fija en Jesús puede hacer cosas imposibles; la que se fija en las tormentas se hunde.' },
  '2026-08-10': { titulo:'San Lorenzo, Diácono y Mártir', libroId:52, libroNombre:'San Juan', capitulo:12, inicio:24, fin:26, explicacion:'Si el grano de trigo no cae en tierra y muere, queda solo; pero si muere da mucho fruto. Lorenzo dio su vida como el grano que muere. El martirio es la forma más radical del seguimiento de Cristo: dar la vida con amor.' },
  '2026-08-15': { titulo:'Asunción de la Virgen María', libroId:51, libroNombre:'San Lucas', capitulo:1, inicio:39, fin:56, explicacion:'María canta el Magníficat: "El Poderoso ha hecho grandes cosas en mí." La Asunción es la participación plena de María en la victoria de su Hijo sobre la muerte. Lo que le ocurrió a ella nos anuncia lo que Dios tiene preparado para todos los que le aman.' },
  '2026-08-16': { titulo:'20º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:15, inicio:21, fin:28, explicacion:'La cananea insiste ante Jesús a favor de su hija enferma. Ante su fe perseverante, Jesús responde: "Grande es tu fe; hágase como deseas." La oración insistente que no se rinde ante las dificultades mueve el corazón de Cristo.' },
  '2026-08-23': { titulo:'21º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:16, inicio:13, fin:20, explicacion:'¿Quién decís vosotros que soy yo? Pedro responde: "Tú eres el Cristo, el Hijo de Dios vivo." Esta confesión es el fundamento de la Iglesia. Cada cristiano está llamado a responder con su vida a la pregunta que Jesús hace a cada uno personalmente.' },
  '2026-08-24': { titulo:'San Bartolomé, Apóstol', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:45, fin:51, explicacion:'Felipe dice a Natanael: "Hemos encontrado a aquel de quien escribieron Moisés y los profetas." Natanael duda: "¿De Nazaret puede salir algo bueno?" Pero cuando Jesús lo llama, él cree. El encuentro personal con Cristo supera todos los prejuicios.' },
  '2026-08-30': { titulo:'22º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:16, inicio:21, fin:27, explicacion:'Jesús anuncia su pasión y Pedro lo reprende. "¡Quítate de mi vista, Satanás!" El que quiera salvar su vida la perderá; el que la pierda por mí la encontrará. El seguimiento de Cristo exige aceptar la cruz como parte del camino.' },

  // ── SEPTIEMBRE ────────────────────────────────────────────────────────────
  '2026-09-06': { titulo:'23º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:18, inicio:15, fin:20, explicacion:'Si tu hermano peca, corrígele en privado; si no escucha, lleva testigos; si no escucha, dilo a la comunidad. La corrección fraterna hecha con amor es un servicio de misericordia. Donde dos o tres se reúnen en mi nombre, allí estoy yo.' },
  '2026-09-13': { titulo:'24º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:18, inicio:21, fin:35, explicacion:'Pedro pregunta cuántas veces perdonar. Jesús responde: setenta veces siete. La parábola del siervo que no perdona muestra la contradicción de quien ha recibido el perdón divino y no lo da. El perdón recibido exige el perdón otorgado.' },
  '2026-09-20': { titulo:'25º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:20, inicio:1, fin:16, explicacion:'Los obreros de la última hora reciben el mismo salario que los de la primera. ¿Son envidiosos porque soy bueno? La generosidad de Dios no sigue la lógica humana de méritos. La salvación es don gratuito para todos los que responden a su llamada.' },
  '2026-09-21': { titulo:'San Mateo, Apóstol y Evangelista', libroId:49, libroNombre:'San Mateo', capitulo:9, inicio:9, fin:13, explicacion:'Jesús ve a Mateo en su puesto de cobrador y le dice: "Sígueme". Y Mateo se levanta y lo sigue. No he venido a llamar a los justos sino a los pecadores. La llamada de Cristo llega a todos; la respuesta inmediata y total es la que lo cambia todo.' },
  '2026-09-27': { titulo:'26º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:21, inicio:28, fin:32, explicacion:'La parábola de los dos hijos: uno dice sí pero no va; el otro dice no pero luego va. Los publicanos y prostitutas entran antes que los sumos sacerdotes en el Reino porque creyeron a Juan. Lo que importa no es la promesa sino el cumplimiento.' },
  '2026-09-29': { titulo:'San Miguel, San Gabriel y San Rafael Arcángeles', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:47, fin:51, explicacion:'Jesús promete a Natanael: "Veréis el cielo abierto y a los ángeles de Dios subir y bajar sobre el Hijo del Hombre." Los ángeles son mensajeros de Dios que actúan en la historia humana. El cielo y la tierra están unidos en Cristo, nueva escala de Jacob.' },

  // ── OCTUBRE ──────────────────────────────────────────────────────────────
  '2026-10-04': { titulo:'27º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:21, inicio:33, fin:43, explicacion:'Los viñadores matan al hijo del dueño para quedarse con la herencia. La piedra desechada se ha convertido en piedra angular. Cristo es rechazado por los suyos pero Dios lo convierte en fundamento de la salvación. El plan de Dios no puede ser frustrado.' },
  '2026-10-11': { titulo:'28º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:22, inicio:1, fin:14, explicacion:'El banquete de bodas rechazado por los invitados y abierto a todos los que están en las plazas. "Muchos son los llamados pero pocos los elegidos." La invitación al Reino es para todos; la respuesta libre y adecuada determina la participación en el banquete.' },
  '2026-10-18': { titulo:'29º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:22, inicio:15, fin:21, explicacion:'Dad al César lo que es del César y a Dios lo que es de Dios. Jesús sale airoso de la trampa. El cristiano tiene deberes civiles y deberes hacia Dios; pero lo que pertenece a Dios — la vida entera — no puede cederlo a ningún poder humano.' },
  '2026-10-25': { titulo:'30º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:22, inicio:34, fin:40, explicacion:'¿Cuál es el mandamiento más importante? Amarás al Señor tu Dios con todo tu corazón y a tu prójimo como a ti mismo. De estos dos mandamientos dependen toda la Ley y los Profetas. Toda la vida cristiana se resume en este doble amor.' },
  '2026-10-28': { titulo:'San Simón y San Judas, Apóstoles', libroId:51, libroNombre:'San Lucas', capitulo:6, inicio:12, fin:19, explicacion:'Jesús pasa la noche en oración antes de elegir a los doce apóstoles. La oración precede a toda decisión importante. Los doce son elegidos entre muchos discípulos: la vocación apostólica viene de Dios y es confirmada por la oración de Jesús.' },

  // ── NOVIEMBRE ────────────────────────────────────────────────────────────
  '2026-11-01': { titulo:'Todos los Santos', libroId:49, libroNombre:'San Mateo', capitulo:5, inicio:1, fin:12, explicacion:'Las Bienaventuranzas describen el retrato de los santos: pobres de espíritu, misericordiosos, limpios de corazón, artífices de paz. Los santos no son superhéroes: son personas ordinarias que vivieron el Evangelio con fidelidad extraordinaria.' },
  '2026-11-02': { titulo:'Todos los Fieles Difuntos', libroId:52, libroNombre:'San Juan', capitulo:11, inicio:17, fin:27, explicacion:'Yo soy la resurrección y la vida; el que cree en mí, aunque haya muerto, vivirá. Hoy recordamos a quienes han muerto en la fe. La muerte no es el final; es el paso a la vida plena prometida por el Resucitado. Oramos por ellos con esperanza.' },
  '2026-11-08': { titulo:'32º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:25, inicio:1, fin:13, explicacion:'La parábola de las diez vírgenes: las prudentes llevan aceite de reserva; las necias no. Velad porque no sabéis el día ni la hora. Vivir la fe con perseverancia es mantener la lámpara encendida hasta que llegue el Señor.' },
  '2026-11-15': { titulo:'33º Domingo Tiempo Ordinario', libroId:49, libroNombre:'San Mateo', capitulo:25, inicio:14, fin:30, explicacion:'La parábola de los talentos: el siervo que enterró el talento es reprendido. Los dones de Dios no son para guardar sino para hacer fructificar. Rendir cuentas al Señor de todo lo que hemos recibido es la perspectiva cristiana ante la vida.' },
  '2026-11-22': { titulo:'Cristo Rey del Universo', libroId:49, libroNombre:'San Mateo', capitulo:25, inicio:31, fin:46, explicacion:'El Rey dice: lo que hicisteis a uno de estos pequeños, a mí me lo hicisteis. Cristo reina desde el servicio. El trono de su reino es la cruz; la corona, la entrega por los pobres. Nuestra relación con los más pequeños determina nuestro lugar ante el Rey.' },
  '2026-11-29': { titulo:'1er Domingo de Adviento — Ciclo B', libroId:51, libroNombre:'San Lucas', capitulo:21, inicio:25, fin:36, expresacion:'Habrá señales en el sol, la luna y las estrellas. Velad y orad en todo momento para que podáis manteneros en pie ante el Hijo del Hombre. El Adviento comienza con la mirada puesta en la venida gloriosa de Cristo.' },
  '2026-11-29': { titulo:'1er Domingo de Adviento — Inicio del Año C', libroId:51, libroNombre:'San Lucas', capitulo:21, inicio:25, fin:36, explicacion:'Habrá señales en el sol, la luna y las estrellas. Velad y orad en todo momento para que podáis manteneros en pie ante el Hijo del Hombre. El Adviento comienza con la mirada puesta en la venida gloriosa de Cristo.' },

  // ── DICIEMBRE ────────────────────────────────────────────────────────────
  '2026-12-06': { titulo:'2º Domingo de Adviento', libroId:51, libroNombre:'San Lucas', capitulo:3, inicio:1, fin:6, explicacion:'La voz del que clama en el desierto: preparad el camino del Señor. Juan el Bautista llama a la conversión. Adviento es tiempo de preparar no solo celebraciones externas sino el camino interior para recibir a Cristo.' },
  '2026-12-08': { titulo:'Inmaculada Concepción de María', libroId:51, libroNombre:'San Lucas', capitulo:1, inicio:26, fin:38, explicacion:'Alégrate, llena de gracia, el Señor está contigo. María fue preservada del pecado desde el primer momento para ser la morada digna del Hijo de Dios. Su "heme aquí" es la respuesta que la Iglesia hace suya en cada generación.' },
  '2026-12-13': { titulo:'3er Domingo de Adviento — Gaudete', libroId:51, libroNombre:'San Lucas', capitulo:3, inicio:10, fin:18, explicacion:'¿Qué debemos hacer? A cada grupo Juan da una respuesta práctica: compartir, no cobrar de más, no extorsionar. El Adviento no es solo espera pasiva sino conversión activa. La alegría del Adviento brota de un corazón que se convierte de verdad.' },
  '2026-12-20': { titulo:'4º Domingo de Adviento', libroId:51, libroNombre:'San Lucas', capitulo:1, inicio:39, fin:45, explicacion:'María visita a su prima Isabel y el niño salta de alegría en su seno. Dichosa la que ha creído. La fe de María hace presente a Cristo donde ella va. Cada cristiano puede llevar a Cristo a los demás cuando vive con fe activa.' },
  '2026-12-25': { titulo:'Navidad del Señor', libroId:51, libroNombre:'San Lucas', capitulo:2, inicio:1, fin:14, explicacion:'Hoy os ha nacido un Salvador que es Cristo el Señor en la ciudad de David. El Hijo eterno de Dios entra en la historia como un niño indefenso. La Navidad celebra el amor de Dios que no se queda a distancia sino que viene a vivir con nosotros.' },
  '2026-12-26': { titulo:'San Esteban, Primer Mártir', libroId:49, libroNombre:'San Mateo', capitulo:10, inicio:17, fin:22, explicacion:'Os entregarán a los tribunales y os azotarán. El que persevere hasta el final se salvará. Esteban fue el primer mártir de la Iglesia. Su muerte en perdón y oración por sus asesinos imita perfectamente la muerte de Cristo.' },
  '2026-12-27': { titulo:'San Juan Evangelista', libroId:52, libroNombre:'San Juan', capitulo:20, inicio:2, fin:8, explicacion:'El discípulo amado corre al sepulcro, ve los lienzos en el suelo y cree. Juan es el testigo privilegiado de la Resurrección. Su Evangelio fue escrito para que creamos que Jesús es el Cristo y para que, creyendo, tengamos vida en su nombre.' },
  '2026-12-28': { titulo:'Santos Inocentes, Mártires', libroId:49, libroNombre:'San Mateo', capitulo:2, inicio:13, fin:18, expresacion:'Herodes manda matar a todos los niños menores de dos años en Belén. Los Santos Inocentes son mártires sin saberlo. La inocencia que muere por causa de Cristo anuncia que el Evangelio siempre encuentra resistencia en los poderes de este mundo.' },
  '2026-12-28': { titulo:'Santos Inocentes, Mártires', libroId:49, libroNombre:'San Mateo', capitulo:2, inicio:13, fin:18, explicacion:'Herodes manda matar a todos los niños menores de dos años en Belén. Los Santos Inocentes son mártires sin saberlo. La inocencia que muere por causa de Cristo anuncia que el Evangelio siempre encuentra resistencia en los poderes de este mundo.' },
  '2026-12-31': { titulo:'Fin de año', libroId:52, libroNombre:'San Juan', capitulo:1, inicio:1, fin:18, explicacion:'En el principio era el Verbo y el Verbo era Dios. Al terminar el año, la Iglesia nos invita a contemplar el origen de todo: Cristo, la Palabra eterna. La historia entera, con sus alegrías y dolores, está sostenida por aquel que es principio y fin.' },
}

// ── Leccionario real de días de semana — Tiempo Ordinario Año II ────────────
// Formato: [libroId, libroNombre, capitulo, inicio, fin, explicacion]
type R = [number, string, number, number, number, string]

// Índice: semana OT → día de semana (1=Lun … 6=Sáb)
const OT_II: Record<number, Record<number, R>> = {
  1: {
    1:[50,'San Marcos',1,14,20,'Jesús proclama que el Reino está cerca y llama a cuatro pescadores. Lo dejan todo para seguirle. La llamada de Cristo es urgente y exige una respuesta total e inmediata.'],
    2:[50,'San Marcos',1,21,28,'Jesús enseña con autoridad y expulsa a un espíritu impuro. La gente queda asombrada: su palabra tiene poder real para liberar. La enseñanza de Jesús no es teoría; transforma vidas.'],
    3:[50,'San Marcos',1,29,39,'Jesús sana a la suegra de Pedro y a muchos enfermos. Al amanecer se retira a orar. La acción apostólica nace de la oración; sin ella se agota. El servicio sostenido por la contemplación es el modelo cristiano.'],
    4:[50,'San Marcos',1,40,45,'Un leproso excluido se postra ante Jesús. Él lo toca y lo sana. Nadie está demasiado impuro para recibir la misericordia de Dios; él siempre sale al encuentro del que se acerca con fe.'],
    5:[50,'San Marcos',2,1,12,'Cuatro amigos bajan a un paralítico por el techo hasta Jesús. Él ve su fe y perdona y sana al enfermo. La amistad que conduce al encuentro con Cristo es el mayor regalo que podemos dar a alguien.'],
    6:[50,'San Marcos',2,13,17,'Jesús llama a Leví el publicano y come con pecadores. "No he venido a llamar a los justos sino a los pecadores." La misericordia de Dios no tiene prejuicios ni fronteras.'],
  },
  2: {
    1:[50,'San Marcos',2,18,22,'No se pone vino nuevo en odres viejos. El Evangelio exige renovación interior. No basta añadir prácticas externas a una vida sin conversión real.'],
    2:[50,'San Marcos',2,23,28,'El sábado fue hecho para el hombre, no el hombre para el sábado. Las leyes religiosas sirven a la persona; la religión auténtica libera, no oprime.'],
    3:[50,'San Marcos',3,1,6,'Jesús sana en sábado a un hombre con la mano paralizada. El amor al prójimo siempre está por encima del legalismo. Ante la rigidez religiosa, Jesús elige siempre la vida y la compasión.'],
    4:[50,'San Marcos',3,7,12,'Multitudes acuden a Jesús desde todas partes. La fama del bien atrae. Nuestro testimonio de vida puede ser el camino que lleva a otros al encuentro con Cristo.'],
    5:[50,'San Marcos',3,13,19,'Jesús sube al monte y elige a los doce para que estén con él y para enviarlos a predicar. Primero el estar con Cristo, luego el ir. El apostolado nace de la intimidad con el Señor.'],
    6:[50,'San Marcos',3,20,21,'La familia de Jesús cree que está fuera de sí. La incomprensión es parte del camino del que sigue a Cristo con radicalidad. El discípulo no puede esperar que todos entiendan su opción de vida.'],
  },
  3: {
    1:[50,'San Marcos',3,22,30,'Los adversarios dicen que Jesús actúa por Beelzebú. Un reino dividido no subsiste. Quien hace el bien en el nombre de Dios viene de Dios; el criterio del árbol es siempre su fruto.'],
    2:[50,'San Marcos',3,31,35,'La madre y los hermanos de Jesús lo buscan. Él señala a sus discípulos: estos son mi familia. La familia de Dios se construye haciendo su voluntad, no solo por vínculos de sangre.'],
    3:[50,'San Marcos',4,1,20,'La parábola del sembrador: la semilla es la misma, los terrenos son distintos. La Palabra de Dios se siembra con generosidad; el fruto depende de la disposición de nuestro corazón.'],
    4:[50,'San Marcos',4,21,25,'La lámpara no se pone bajo el celemín sino sobre el candelero. La fe no es algo privado que se esconde; está llamada a iluminar. Lo que recibimos de Dios es para darlo, no para guardarlo.'],
    5:[50,'San Marcos',4,26,34,'El Reino de Dios crece solo, como la semilla. No todo depende de nuestro esfuerzo; hay una fuerza divina que actúa silenciosamente en la historia y en los corazones.'],
    6:[50,'San Marcos',4,35,41,'En la tormenta Jesús calma el viento y el mar. "¿Por qué tenéis miedo? ¿No tenéis fe?" Su presencia en nuestra barca no elimina las tormentas pero trae una paz que supera toda comprensión.'],
  },
  4: {
    1:[50,'San Marcos',5,1,20,'Jesús libera al endemoniado de Gerasa. La liberación es completa: el hombre queda sentado, vestido y en su sano juicio. Cristo viene a restaurar la dignidad del ser humano en todas sus dimensiones.'],
    2:[50,'San Marcos',5,21,43,'Jesús resucita a la hija de Jairo y sana a la mujer con hemorragias. "No temas, solo ten fe." Jesús sale al encuentro de la muerte y la enfermedad con la fuerza del amor de Dios.'],
    3:[50,'San Marcos',6,1,6,'En Nazaret no puede hacer milagros por la falta de fe. La familiaridad puede cerrar los ojos ante lo sagrado. La fe exige apertura y humildad para ver a Dios actuando cerca de nosotros.'],
    4:[50,'San Marcos',6,7,13,'Jesús envía a los doce de dos en dos con autoridad sobre los espíritus impuros. Los envía sin equipaje: la misión se hace confiando en Dios, no en los propios recursos.'],
    5:[50,'San Marcos',6,14,29,'El martirio de Juan el Bautista: murió por no callar ante la injusticia del poderoso. El profeta auténtico dice la verdad aunque le cueste la vida.'],
    6:[50,'San Marcos',6,30,34,'Los apóstoles regresan y Jesús los invita a descansar. Pero al ver la multitud como ovejas sin pastor, siente compasión. El descanso y la misión se equilibran; el motor de todo es la compasión.'],
  },
  5: {
    1:[50,'San Marcos',6,53,56,'En todos los lugares adonde llegaba Jesús la gente lo reconocía y corría a tocar el borde de su manto. ¿Cuánto deseo hay en mi corazón de estar cerca de Jesús? La fe activa busca el contacto con el Señor.'],
    2:[50,'San Marcos',7,1,13,'Jesús critica a los fariseos por anteponer la tradición humana al mandamiento de Dios. Lo que honra a Dios no son los ritos vacíos sino el corazón que ama de verdad.'],
    3:[50,'San Marcos',7,14,23,'Lo que contamina no viene de fuera sino de dentro del corazón. La conversión verdadera comienza en lo más profundo de nuestra interioridad, no en los gestos externos.'],
    4:[50,'San Marcos',7,24,30,'La mujer sirofenicia no se rinde ante la respuesta difícil de Jesús. Su humildad y persistencia logran lo que pedía. La oración perseverante es siempre escuchada.'],
    5:[50,'San Marcos',7,31,37,'Jesús sana a un sordomudo: "Ábrete." Él quiere abrir nuestros oídos a su Palabra y nuestra boca para proclamarla. La misma gracia que curó al sordomudo actúa en cada bautizado.'],
    6:[50,'San Marcos',8,1,10,'Jesús alimenta a cuatro mil personas con siete panes. Siente compasión de la multitud que lleva días con él. Dios ve nuestra hambre, física y espiritual, y tiene poder para saciarla.'],
  },
  6: {
    1:[50,'San Marcos',8,11,13,'Los fariseos piden a Jesús una señal del cielo. Él se niega. La fe no necesita señales espectaculares; se nutre de la Palabra y los sacramentos. Pedir señales como condición para creer no es fe.'],
    2:[50,'San Marcos',8,14,21,'La levadura de los fariseos: haber visto los milagros no basta si el corazón permanece cerrado. La comprensión del Evangelio no es fruto de la inteligencia sino de la apertura del corazón.'],
    3:[50,'San Marcos',8,22,26,'Jesús sana a un ciego de Betsaida en dos etapas. La fe puede crecer gradualmente; lo importante es que avance hacia la visión plena. Dios respeta nuestro ritmo de conversión.'],
    4:[50,'San Marcos',8,27,33,'Pedro confiesa que Jesús es el Cristo pero rechaza la cruz. "¡Quítate de mi vista, Satanás!" Seguir a Cristo exige aceptar que el camino a la gloria pasa por la entrega.'],
    5:[50,'San Marcos',8,34,38,'El que quiera salvar su vida la perderá; el que la pierda por mí la encontrará. El seguimiento de Cristo exige tomar la propia cruz. La lógica del Evangelio invierte la lógica del mundo.'],
    6:[50,'San Marcos',9,2,13,'La Transfiguración: Jesús se transfigura ante Pedro, Santiago y Juan. El Padre proclama: "Este es mi Hijo amado, escuchadle." La gloria de Cristo anticipa la Resurrección y sostiene en los momentos de prueba.'],
  },
  7: {
    1:[50,'San Marcos',9,14,29,'Jesús libera a un muchacho que sus discípulos no pudieron curar. "Esta clase no puede ser expulsada más que con oración." Hay situaciones que solo se resuelven con oración profunda y confiada.'],
    2:[50,'San Marcos',9,30,37,'Jesús anuncia su pasión y los discípulos discuten quién es el mayor. Él pone a un niño en medio: el que quiera ser el primero sea el servidor de todos. La grandeza del Reino se mide por el servicio.'],
    3:[50,'San Marcos',9,38,40,'El que no está contra nosotros está a favor de nosotros. Jesús amplía la perspectiva de sus discípulos: el bien puede venir de fuera del grupo. No hay monopolio del Espíritu.'],
    4:[50,'San Marcos',9,41,50,'Si tu mano te escandaliza, córtala. Las imágenes radicales de Jesús invitan a tomar en serio el combate espiritual. La sal que pierde su sabor no sirve. Que cada uno tenga sal en sí mismo.'],
    5:[50,'San Marcos',10,1,12,'Lo que Dios unió no lo separe el hombre. Jesús defiende la indisolubilidad del matrimonio. El matrimonio cristiano es signo del amor fiel e irrevocable de Dios a su pueblo.'],
    6:[50,'San Marcos',10,13,16,'Dejad que los niños vengan a mí. El Reino de Dios es de quienes son como ellos. La confianza total del niño en sus padres es modelo de nuestra relación con el Padre celestial.'],
  },
  8: {
    1:[50,'San Marcos',10,17,27,'El joven rico se va triste por sus muchos bienes. Es más fácil que un camello pase por el ojo de una aguja que un rico entre en el Reino. El desapego de los bienes materiales es condición del discipulado.'],
    2:[50,'San Marcos',10,28,31,'Pedro recuerda que lo han dejado todo. Jesús promete el ciento por uno en esta vida y la vida eterna. La generosidad con Dios nunca queda sin respuesta.'],
    3:[50,'San Marcos',10,32,45,'Los hijos de Zebedeo piden los primeros puestos. Jesús responde: el que quiera ser grande sea servidor. El Hijo del Hombre no vino a ser servido sino a servir y dar su vida como rescate.'],
    4:[50,'San Marcos',10,46,52,'El ciego Bartimeo grita sin parar: "Hijo de David, ten compasión de mí." Jesús lo llama y le pregunta qué quiere. Inmediatamente recobra la vista y lo sigue. La oración insistente que no se rinde es siempre escuchada.'],
    5:[50,'San Marcos',11,11,26,'Jesús maldice la higuera sin frutos y expulsa a los vendedores del Templo. La religiosidad sin fruto real de amor es un árbol sin higos. La casa de Dios debe ser casa de oración, no negocio.'],
    6:[50,'San Marcos',11,27,33,'Los jefes pregunta por qué autoridad actúa Jesús. Él responde con otra pregunta sobre el bautismo de Juan. La autoridad de Jesús no viene de los hombres sino del Padre que lo envía.'],
  },
  9: {
    1:[50,'San Marcos',12,1,12,'La parábola de los viñadores homicidas: matan al hijo del dueño para quedarse con la herencia. La piedra desechada es la piedra angular. Cristo rechazado por los suyos se convierte en fundamento de salvación.'],
    2:[50,'San Marcos',12,13,17,'Dad al César lo que es del César y a Dios lo que es de Dios. Jesús sale airoso de la trampa. Lo que pertenece a Dios —la vida entera— no puede cederse a ningún poder humano.'],
    3:[50,'San Marcos',12,18,27,'Jesús responde a los saduceos sobre la resurrección. Dios no es Dios de muertos sino de vivos. La vida después de la muerte supera toda categoría humana; es comunión plena con Dios.'],
    4:[50,'San Marcos',12,28,34,'El primer mandamiento es amar a Dios con todo el corazón y al prójimo como a uno mismo. "No estás lejos del Reino de Dios." La doble caridad es el corazón de todo el Evangelio.'],
    5:[50,'San Marcos',12,35,37,'Jesús pregunta cómo el Cristo puede ser hijo de David si David lo llama Señor. La identidad de Jesús supera las expectativas humanas. Cristo es Señor, no solo descendiente de David.'],
    6:[50,'San Marcos',12,38,44,'Jesús contrasta la ostentación de los escribas con la ofrenda de la viuda que da todo lo que tiene. La generosidad que nace del sacrificio personal es la que agrada a Dios.'],
  },
  10: {
    1:[51,'San Lucas',10,25,37,'La parábola del buen samaritano responde quién es el prójimo. El prójimo es todo el que necesita ayuda sin fronteras de raza o religión. La misericordia concreta es el corazón del Evangelio.'],
    2:[51,'San Lucas',10,38,42,'Marta se afana en los servicios mientras María escucha a Jesús. María ha elegido la parte mejor. El Señor invita a que toda actividad nazca de la escucha de su Palabra.'],
    3:[51,'San Lucas',11,1,4,'Los discípulos piden a Jesús que les enseñe a orar. Él les da el Padre Nuestro. Esta oración recoge todo lo que el discípulo necesita: la gloria de Dios y las necesidades del hombre.'],
    4:[51,'San Lucas',11,5,13,'Pedid y recibiréis, buscad y encontraréis. Si vosotros siendo malos sabéis dar cosas buenas a vuestros hijos, cuánto más el Padre dará el Espíritu Santo a los que se lo pidan.'],
    5:[51,'San Lucas',11,15,26,'Jesús responde a los que le acusan de actuar por Beelzebú. El que no recoge conmigo desparrama. La fe en Jesús exige una posición clara; no hay neutralidad ante él.'],
    6:[51,'San Lucas',11,27,28,'Una mujer dice bienaventurado el vientre que te llevó. Jesús responde: dichosos más bien los que escuchan la Palabra de Dios y la guardan. La bienaventuranza de María es espiritual, modelo para todos.'],
  },
  11: {
    1:[51,'San Lucas',11,29,32,'Esta generación pide una señal. La única señal es la de Jonás. El que predica no es mayor que Jonás pero el que escucha tiene ante sí algo más grande que Salomón o Jonás.'],
    2:[51,'San Lucas',11,37,41,'Los fariseos se escandalizan porque Jesús no se lavó antes de comer. Él les reprocha limpiar el exterior mientras el interior está lleno de codicia. La pureza que Dios pide es la del corazón.'],
    3:[51,'San Lucas',11,42,46,'¡Ay de vosotros fariseos que pagáis el diezmo de la menta y descuidáis la justicia y el amor de Dios! La religiosidad exterior que descuida lo esencial es hipocresía que el Señor condena.'],
    4:[51,'San Lucas',11,47,54,'Ay de vosotros que construís los sepulcros de los profetas a quienes vuestros padres mataron. La historia se repite cuando rechazamos los mensajeros de Dios que vienen a corregirnos.'],
    5:[51,'San Lucas',12,1,7,'Guardaos de la levadura de los fariseos que es la hipocresía. No hay nada encubierto que no sea revelado. Hasta los cabellos de vuestra cabeza están contados: no temáis.'],
    6:[51,'San Lucas',12,8,12,'Todo el que me confiese ante los hombres, yo lo confesaré ante los ángeles de Dios. El Espíritu Santo os enseñará en el momento oportuno lo que hay que decir. La valentía cristiana viene del Espíritu.'],
  },
  12: {
    1:[51,'San Lucas',12,13,21,'La parábola del rico necio: esa noche le piden el alma. Así el que amasa tesoros para sí y no es rico ante Dios. La vida no consiste en los bienes que uno posee sino en la riqueza del corazón.'],
    2:[51,'San Lucas',12,35,38,'Estad con las cinturas ceñidas y las lámparas encendidas. El señor que vuelve tarde de noche y encuentra a sus siervos velando los pondrá a servir en su mesa. La vigilancia cristiana es actitud de amor.'],
    3:[51,'San Lucas',12,39,48,'Velaría si supiera a qué hora viene el ladrón. Al que mucho se le da, mucho se le pedirá. La responsabilidad cristiana crece con los dones recibidos de Dios.'],
    4:[51,'San Lucas',12,49,53,'He venido a traer fuego a la tierra. ¿Pensáis que vine a traer paz? No, sino división. El Evangelio exige opciones radicales que pueden generar incomprensión incluso en el propio hogar.'],
    5:[51,'San Lucas',12,54,59,'Sabéis juzgar el aspecto de la tierra y el cielo pero no juzgáis este tiempo. Jesús invita a leer los signos del tiempo con el corazón abierto a la gracia que Dios ofrece hoy.'],
    6:[51,'San Lucas',13,1,9,'Si no os convertís pereceréis todos de la misma manera. La parábola de la higuera estéril: el labrador pide un año más de paciencia. El tiempo de la gracia es un don precioso que no hay que desperdiciar.'],
  },
  13: {
    1:[51,'San Lucas',13,10,17,'Jesús libera en sábado a una mujer encorvada dieciocho años. La misericordia tiene siempre razón sobre el legalismo. La persona vale más que cualquier norma religiosa.'],
    2:[51,'San Lucas',13,18,21,'El Reino de Dios es como un grano de mostaza que crece hasta ser árbol, y como levadura que fermenta toda la masa. Lo pequeño y aparentemente insignificante de la fe es capaz de transformarlo todo.'],
    3:[51,'San Lucas',13,22,30,'Esforzaos en entrar por la puerta estrecha. Habrá primeros que serán últimos y últimos que serán primeros. El Reino de Dios no se hereda automáticamente; exige conversión y compromiso real.'],
    4:[51,'San Lucas',13,31,35,'Herodes quiere matar a Jesús. Él responde: no puede ser que un profeta muera fuera de Jerusalén. Jesús avanza libremente hacia su destino con la serenidad del que cumple la misión del Padre.'],
    5:[51,'San Lucas',14,1,6,'Jesús sana en sábado a un hidrópico. Pregunta a los presentes si sería lícito sacarlo del pozo en sábado. La lógica de la misericordia siempre supera la rigidez de la ley.'],
    6:[51,'San Lucas',14,1,11,'Cuando seas invitado a bodas no te pongas en el primer puesto. El que se humille será exaltado. La humildad que busca el último lugar es la que Dios exalta en su Reino.'],
  },
  14: {
    1:[51,'San Lucas',14,12,14,'Cuando hagas un banquete invita a los pobres y a los que no pueden devolverte nada. Te será recompensado en la resurrección de los justos. La generosidad sin esperar retorno es la que agrada a Dios.'],
    2:[51,'San Lucas',14,15,24,'La parábola del gran banquete: los invitados ponen excusas. El señor manda llenar su casa con los pobres y marginados. El Reino de Dios está abierto para quienes responden a la invitación con generosidad.'],
    3:[51,'San Lucas',14,25,33,'El que no lleva su cruz y me sigue no puede ser mi discípulo. Hay que calcular el costo antes de seguir a Jesús. El seguimiento auténtico exige una decisión consciente y totalizante.'],
    4:[51,'San Lucas',15,1,10,'La oveja perdida y la moneda perdida: hay más alegría en el cielo por un pecador que se convierte. Dios busca al perdido con amor incansable y celebra su regreso con fiesta.'],
    5:[51,'San Lucas',16,1,8,'La parábola del administrador astuto: los hijos de este mundo son más listos que los hijos de la luz. Jesús invita a usar los bienes con la misma habilidad pero al servicio del bien eterno.'],
    6:[51,'San Lucas',16,9,15,'Haceos amigos con el dinero injusto. No podéis servir a Dios y al dinero. Los fariseos que aman el dinero escuchan esto y se burlan. Dios conoce los corazones y lo que los hombres estiman es abominable ante él.'],
  },
  15: {
    1:[51,'San Lucas',16,19,31,'El rico Epulón y Lázaro: después de la muerte los papeles se invierten. La indiferencia ante el sufrimiento del prójimo tiene consecuencias eternas. "Tienen a Moisés y los profetas; que los escuchen."'],
    2:[51,'San Lucas',17,1,6,'Si tu hermano peca, corrígele; si se arrepiente, perdónale. Con fe del tamaño de un grano de mostaza se mueven montañas. La fe genuina hace posible lo que parece imposible.'],
    3:[51,'San Lucas',17,7,10,'Cuando hayáis hecho todo lo que se os mandó, decid: somos siervos inútiles, hemos hecho lo que debíamos. La humildad es la medida exacta del servicio cristiano: no hay mérito que reclamar ante Dios.'],
    4:[51,'San Lucas',17,11,19,'Jesús sana a diez leprosos pero solo uno, un samaritano, regresa a dar gracias. ¿Dónde están los otros nueve? La gratitud es expresión de fe madura y reconocimiento del don recibido.'],
    5:[51,'San Lucas',17,26,37,'Como en los días de Noé: comían, bebían, se casaban hasta que llegó el diluvio. Estad preparados porque el Hijo del Hombre vendrá a la hora que no pensáis. La vigilancia es estilo de vida cristiano.'],
    6:[51,'San Lucas',18,1,8,'La parábola de la viuda que insiste ante el juez injusto. Dios hará justicia a sus elegidos que claman a él día y noche. La oración perseverante que no se rinde mueve la mano de Dios.'],
  },
  16: {
    1:[51,'San Lucas',18,9,14,'El fariseo y el publicano en el Templo. El que se humilla será exaltado. "Ten piedad de mí que soy pecador": esta es la oración que Dios escucha. La humildad es el primer paso de la fe.'],
    2:[51,'San Lucas',18,35,43,'El ciego de Jericó grita sin parar: "Hijo de David, ten compasión de mí." Jesús pregunta qué quiere y le devuelve la vista. La oración audaz y perseverante ante Cristo siempre es escuchada.'],
    3:[51,'San Lucas',19,1,10,'Zaqueo sube a un árbol para ver a Jesús. Jesús lo llama por su nombre e insiste en ir a su casa. La presencia de Cristo transforma la vida del pecador. Hoy ha llegado la salvación a esta casa.'],
    4:[51,'San Lucas',19,11,28,'La parábola de las minas: cada siervo recibe una mina para negociarla. Al que tiene se le dará más. Los dones de Dios son para hacerlos fructificar al servicio del Reino, no para guardarlos por miedo.'],
    5:[51,'San Lucas',20,27,40,'Los saduceos preguntan sobre la resurrección. Dios no es Dios de muertos sino de vivos; para él todos viven. La vida eterna supera toda categoría humana y lleva a la comunión plena con Dios.'],
    6:[51,'San Lucas',21,1,4,'La viuda que echa dos monedas pequeñas en el tesoro del Templo. Jesús dice que echó más que todos porque dio todo lo que tenía para vivir. La ofrenda que sale del sacrificio personal agrada a Dios.'],
  },
  17: {
    1:[51,'San Lucas',10,25,37,'La parábola del buen samaritano: ama al prójimo con obras concretas sin fronteras de raza ni religión. El amor cristiano no es sentimiento sino decisión que se hace carne en el servicio.'],
    2:[51,'San Lucas',12,13,21,'La parábola del rico necio: no acumules tesoros para ti que no eres rico ante Dios. La riqueza de la vida no se mide por los bienes poseídos sino por la generosidad con Dios y el prójimo.'],
    3:[51,'San Lucas',12,35,40,'Estad con las lámparas encendidas esperando al señor que vuelve. La vigilancia cristiana no es ansiedad sino amor que espera con alegría la venida del Señor.'],
    4:[51,'San Lucas',13,10,17,'La mujer encorvada liberada en sábado. No convenía dejar sin soltar a esta hija de Abraham dieciocho años. La misericordia de Dios no entiende de días ni de restricciones legales.'],
    5:[51,'San Lucas',14,1,6,'Jesús sana en sábado al hidrópico ante los fariseos. La misericordia hacia el que sufre tiene siempre prioridad sobre la observancia literal de la ley.'],
    6:[51,'San Lucas',15,1,10,'Un pastor deja noventa y nueve ovejas para buscar una perdida. Una mujer busca hasta encontrar la moneda perdida. Así Dios busca a cada persona con amor incansable hasta encontrarla.'],
  },
  18: {
    1:[51,'San Lucas',16,19,31,'El rico festeja cada día espléndidamente mientras Lázaro mendiga a su puerta. La indiferencia ante el prójimo que sufre ciega el corazón para Dios. Las Escrituras ya nos dicen todo lo necesario para convertirse.'],
    2:[51,'San Lucas',17,7,10,'Cuando hayamos hecho todo lo que debíamos, somos siervos inútiles. No hay mérito que reclamar ante la gratuidad de Dios. Toda nuestra vida es respuesta a un amor que nos precedió.'],
    3:[51,'San Lucas',18,1,8,'La viuda insistente y el juez injusto. Dios hará justicia a sus elegidos sin tardar. La oración confiada y perseverante es la respuesta de la fe a las situaciones de injusticia y sufrimiento.'],
    4:[51,'San Lucas',18,9,14,'El fariseo da gracias por sus méritos; el publicano pide misericordia. El que se humilla será exaltado. La oración auténtica nace del reconocimiento de nuestra pequeñez ante Dios.'],
    5:[51,'San Lucas',19,1,10,'Zaqueo busca a Jesús y Jesús lo busca a él. El encuentro personal con Cristo transforma la vida radicalmente: Zaqueo devuelve el cuádruplo y da la mitad a los pobres.'],
    6:[51,'San Lucas',20,1,8,'Los jefes preguntan a Jesús con qué autoridad actúa. Él responde con otra pregunta. La autoridad de Cristo no viene de los hombres sino del Padre que lo envió al mundo.'],
  },
  19: {
    1:[51,'San Lucas',10,38,42,'María se sienta a los pies de Jesús y escucha su Palabra. Ha elegido la parte mejor. La escucha contemplativa de la Palabra de Dios es el fundamento de toda actividad cristiana fecunda.'],
    2:[51,'San Lucas',11,5,13,'Si un amigo pide a medianoche pan, el otro se levanta y lo da. Cuánto más el Padre celestial da cosas buenas a los que se las piden. La oración confiada en el amor paternal de Dios es siempre escuchada.'],
    3:[51,'San Lucas',12,49,53,'He venido a traer fuego a la tierra. El Evangelio provoca divisiones cuando se toma en serio. La paz de Cristo no es ausencia de tensión sino unidad en la verdad y el amor.'],
    4:[51,'San Lucas',13,22,30,'La puerta estrecha. No basta decir Señor Señor o haber comido en tu presencia. Lo que salva es la obediencia a la voluntad de Dios expresada en la vida concreta de cada día.'],
    5:[51,'San Lucas',14,25,33,'El discipulado tiene un costo: hay que llevarlo todo en cuenta como el constructor o el rey que va a la guerra. Seguir a Cristo sin calcular el precio es no tomarlo en serio.'],
    6:[51,'San Lucas',16,1,8,'El administrador prudente. Los hijos de este mundo son más astutos que los hijos de la luz. Jesús invita a usar todas las capacidades y recursos al servicio del Reino de Dios.'],
  },
  20: {
    1:[51,'San Lucas',11,29,32,'La señal de Jonás: el Hijo del Hombre estará tres días en el corazón de la tierra. La Resurrección es la señal definitiva de Dios al mundo. Quien la acepta con fe tiene más que todos los tesoros del mundo.'],
    2:[51,'San Lucas',12,39,48,'Al que mucho se le da, mucho se le exigirá. La responsabilidad ante Dios crece en proporción a los dones recibidos. El discípulo consciente de sus talentos vive con mayor generosidad y fidelidad.'],
    3:[51,'San Lucas',13,31,35,'Herodes quiere matar a Jesús. Él responde que seguirá curando y echando demonios hasta el tercer día. Jesús avanza sereno hacia su destino porque hace la voluntad del Padre.'],
    4:[51,'San Lucas',17,20,25,'El Reino de Dios no viene con signos visibles ni está aquí o allí. El Reino de Dios está entre vosotros. La presencia de Cristo en medio de los suyos es el mayor bien que puede poseer el cristiano.'],
    5:[51,'San Lucas',18,35,43,'El ciego de Jericó que grita sin parar logra su curación por su fe. Jesús le pregunta: ¿qué quieres que te haga? La oración específica y confiada obtiene respuesta del Señor.'],
    6:[51,'San Lucas',19,11,28,'Las minas: el señor pide cuentas de lo recibido. Al que tiene se le dará más. Cada don recibido de Dios es una semilla para hacer fructificar en beneficio del Reino y los demás.'],
  },
  21: {
    1:[51,'San Lucas',10,25,37,'Al final del Tiempo Ordinario, el buen samaritano sigue siendo el modelo del amor cristiano: concreto, sin fronteras y sin esperar recompensa. Ve y haz tú lo mismo.'],
    2:[51,'San Lucas',13,22,30,'Muchos intentarán entrar y no podrán. La puerta estrecha exige conversión real, no solo conocimiento superficial de Jesús. La salvación es don gratuito que exige nuestra respuesta libre y generosa.'],
    3:[51,'San Lucas',14,12,14,'No invites a los ricos sino a los pobres que no pueden devolverlo. El cristiano que actúa con generosidad gratuita anticipa ya en esta vida el banquete eterno del Reino.'],
    4:[51,'San Lucas',17,1,6,'Si tu hermano peca perdónale. Con fe como grano de mostaza se arrancan árboles y se plantan en el mar. La fe unida al perdón fraterno tiene un poder que supera toda expectativa humana.'],
    5:[51,'San Lucas',19,1,10,'El Hijo del Hombre vino a buscar y salvar lo que estaba perdido. Zaqueo representa a todo pecador buscado por Cristo. Nadie está demasiado perdido para ser encontrado por el amor de Dios.'],
    6:[51,'San Lucas',20,27,40,'La resurrección supera toda categoría humana. En Dios todos están vivos. Al terminar el Tiempo Ordinario contemplamos el destino eterno al que Dios nos llama: la vida plena con él para siempre.'],
  },
}
// Para semanas 22-34, continuar con Lucas capítulos finales
function getWeekReading(week: number, day: number): R | null {
  if (OT_II[week] && OT_II[week][day]) return OT_II[week][day]
  // Semanas 22-34: pasajes finales de Lucas sobre el fin de los tiempos
  const lateReadings: Record<number, R> = {
    1:[51,'San Lucas',21,1,4,'La viuda y las dos monedas: ella dio todo lo que tenía. La generosidad que brota del sacrificio personal es la más preciosa a los ojos de Dios.'],
    2:[51,'San Lucas',21,5,11,'Jesús anuncia la destrucción del Templo y los signos del fin. No os dejéis engañar; estas cosas deben ocurrir pero el fin no llegará enseguida. La historia está en manos de Dios.'],
    3:[51,'San Lucas',21,12,19,'Os entregarán y os perseguirán. Con vuestra perseverancia salvaréis vuestras almas. La fidelidad a Cristo en medio de la prueba es el testimonio más poderoso de la fe.'],
    4:[51,'San Lucas',21,20,28,'Cuando veáis acercarse vuestra liberación, levantad la cabeza. El cristiano no mira el futuro con temor sino con esperanza; la venida de Cristo es siempre buena noticia.'],
    5:[51,'San Lucas',21,29,33,'La generación no pasará sin que todo esto ocurra. El cielo y la tierra pasarán pero mis palabras no pasarán. La Palabra de Dios es el fundamento eterno sobre el que se construye la vida cristiana.'],
    6:[51,'San Lucas',21,34,36,'Velad y orad en todo tiempo para poder manteneros en pie ante el Hijo del Hombre. La vigilancia cristiana es la actitud permanente del discípulo que espera a su Señor con amor y fidelidad.'],
  }
  return lateReadings[day] || null
}

// ── Función principal ────────────────────────────────────────────────────────

// Fechas clave 2026
const BAPTISM_MON   = new Date('2026-01-12T12:00:00') // Lunes tras Bautismo
const ASH_WED       = new Date('2026-02-18T12:00:00')
const PENTECOST_SUN = new Date('2026-05-24T12:00:00')
const WEEK8_TUE     = new Date('2026-05-26T12:00:00') // Semana 8 empieza mar (lun=fiesta María)
const WEEK9_MON     = new Date('2026-06-01T12:00:00') // Semana 9 empieza lunes
const ADVENT_SUN    = new Date('2026-11-29T12:00:00')

export function getGospelForDate(dateStr: string): GospelEntry | null {
  // 1. Entradas específicas (domingos, fiestas, días especiales de Cuaresma/Pascua)
  if (SPECIFIC[dateStr]) return SPECIFIC[dateStr]

  const d = new Date(dateStr + 'T12:00:00')
  const dow = d.getDay() // 0=Dom … 6=Sáb

  // 2. Tiempo Ordinario antes de Cuaresma (Lun 12 ene – Mar 17 feb)
  if (d >= BAPTISM_MON && d < ASH_WED) {
    const weekNum = Math.floor((d.getTime() - BAPTISM_MON.getTime()) / (7 * 86400000)) + 1
    const r = getWeekReading(weekNum, dow === 0 ? 7 : dow)
    if (r) {
      const [lid, lnom, cap, ini, fin, exp] = r
      return { titulo:`Semana ${weekNum} — Tiempo Ordinario`, libroId:lid, libroNombre:lnom, capitulo:cap, inicio:ini, fin:fin, explicacion:exp }
    }
  }

  // 3. Días de semana Sem.8 tras Pentecostés (Mar 26 – Sáb 30 mayo)
  if (d >= WEEK8_TUE && d < WEEK9_MON && dow !== 0) {
    const r = getWeekReading(8, dow)
    if (r) {
      const [lid, lnom, cap, ini, fin, exp] = r
      return { titulo:'Semana 8 — Tiempo Ordinario', libroId:lid, libroNombre:lnom, capitulo:cap, inicio:ini, fin:fin, explicacion:exp }
    }
  }

  // 4. Tiempo Ordinario tras Pentecostés (Lun 1 jun – Sáb 28 nov)
  if (d >= WEEK9_MON && d < ADVENT_SUN) {
    const weekNum = Math.floor((d.getTime() - WEEK9_MON.getTime()) / (7 * 86400000)) + 9
    const r = getWeekReading(weekNum, dow === 0 ? 7 : dow)
    if (r) {
      const [lid, lnom, cap, ini, fin, exp] = r
      return { titulo:`Semana ${weekNum} — Tiempo Ordinario`, libroId:lid, libroNombre:lnom, capitulo:cap, inicio:ini, fin:fin, explicacion:exp }
    }
  }

  return null
}
